ng","size":"75","effect":"none","newTab":"false","linkUrl":"","variant":"logo","alignment":"left","borderColor":"#c5a059","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"2","horizontalOffset":"0"}}],"alignment":"left","canonical":true,"isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"center","center":"left"},"cellShadow":{"left":"none","right":"none","center":"none"},"cellVAlign":{"left":"top","right":"top","center":"center"},"cellOpacity":{"left":"1","right":"1","center":"1"},"cellPadding":{"left":"0","right":"0","center":"0"},"marginBottom":"20","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false","center":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","savedSectionId":"saved_section_1781826409772_rcsh6r","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"center":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#d9e4ef","right":"#999999","center":"#ffffff"},"cellBorderStyle":{"left":"solid","right":"solid","center":"solid"},"cellBorderWidth":{"left":"0","right":"0","center":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"0","right":"14","center":"20"},"cellMobileHidden":{"left":"false","right":"false","center":"false"},"cellDesktopHidden":{"left":"false","right":"false","center":"false"},"cellVerticalMargin":{"left":"0","right":"0","center":"0"}},{"id":"348037cd-5139-48ea-86f2-3a03d32d4242","title":"Content Block 1","layout":"two-column","locked":false,"modules":[{"id":"module-ae640e95-5fca-45de-aaea-7ba97866a0d2","name":"","text":"<h1>Privacy Policy</h1><h2>Marinoff &amp; Associates, P.C.</h2><p>At Marinoff &amp; Associates, P.C., we respect your privacy and are committed to protecting the personal information you share with us. This Privacy Policy explains how we may collect, use, and safeguard information submitted through our website, contact forms, phone calls, emails, or other communications with our office.</p><p>By using this website, you agree to the terms of this Privacy Policy.</p><h2>Information We May Collect</h2><p>When you contact Marinoff &amp; Associates, P.C., we may collect personal information that you voluntarily provide, including your name, phone number, email address, mailing address, and details related to your legal inquiry. We may also collect basic website usage information such as browser type, pages visited, device information, and general location data through standard website analytics tools.</p><p>Please do not submit highly sensitive or confidential information through the website contact form unless requested by our office.</p><h2>How We Use Your Information</h2><p>We may use the information you provide to:</p><ul><li><p>Respond to your inquiries</p></li><li><p>Schedule consultations</p></li><li><p>Communicate with you about your legal matter</p></li><li><p>Provide legal services if an attorney-client relationship is established</p></li><li><p>Improve our website and client service experience</p></li><li><p>Maintain internal records</p></li><li><p>Comply with legal, ethical, or professional obligations</p></li></ul><p>Submitting information through this website does not automatically create an attorney-client relationship. An attorney-client relationship is formed only after Marinoff &amp; Associates, P.C. agrees to represent you and any required agreements are completed.</p><h2>Confidentiality and Security</h2><p>We take reasonable steps to protect personal information from unauthorized access, misuse, disclosure, or loss. However, no website, email system, or online transmission is completely secure. For that reason, you should avoid sending confidential or time-sensitive legal information through this website without first speaking directly with our office.</p><p>Information shared with our firm after an attorney-client relationship has been established is handled in accordance with applicable legal and ethical duties of confidentiality.</p><h2>Sharing of Information</h2><p>Marinoff &amp; Associates, P.C. does not sell or rent your personal information. We may share information only when necessary to operate our business, provide legal services, comply with the law, protect our rights, or work with trusted service providers who assist with website hosting, communications, analytics, or administrative functions.</p><h2>Cookies and Website Analytics</h2><p>Our website may use cookies, analytics tools, or similar technologies to understand how visitors use the site and to improve performance. You may adjust your browser settings to disable cookies, though some website features may not function properly.</p><h2>Third-Party Links</h2><p>This website may contain links to third-party websites. Marinoff &amp; Associates, P.C. is not responsible for the privacy practices, content, or security of external websites. We encourage you to review the privacy policies of any third-party sites you visit.</p><h2>Your Choices</h2><p>You may contact our office to request that we update or correct your contact information. You may also ask us to stop sending non-essential communications. We may retain certain information as required for legal, ethical, business, or recordkeeping purposes.</p><h2>Children’s Privacy</h2><p>This website is intended for general audiences and is not directed toward children. We do not knowingly collect personal information from children through this website.</p><h2>Changes to This Privacy Policy</h2><p>Marinoff &amp; Associates, P.C. may update this Privacy Policy from time to time. Any updates will be posted on this page with a revised effective date.</p><h2>Contact Us</h2><p>If you have questions about this Privacy Policy or how your information is handled, please contact us:</p><p><strong>Marinoff &amp; Associates, P.C.</strong><br><strong>Westminster:</strong> 10455 Sheridan Blvd., Suite 210, Westminster, CO 80020<br><strong>Brighton:</strong> 150 South 4th Avenue, Suite 200, Brighton, CO 80601<br><strong>Greeley:</strong> 609 8th Street, Suite 200, Greeley, CO 80631</p><p><strong>Phone:</strong> 720-373-3508<br><strong>Additional Phone:</strong> 720-216-4766<br><strong>Website:</strong> <a target=\"_blank\" rel=\"noopener noreferrer\" href=\"http://www.brandonmarinoff.com\">www.brandonmarinoff.com</a></p><p><strong>Se Habla Español</strong></p><p><em>This Privacy Policy is provided for general informational purposes and should be reviewed by legal counsel to ensure compliance with all applicable laws and regulations.</em></p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"86aa7632-5560-46ab-b6f7-d401d6ff04a3","name":"Justice","text":"","type":"image","column":"right","settings":{"alt":"Justice","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1782582196540_Expereinced_Immigration_Attorneys.png","altText":"Image","linkUrl":"","imageUrl":"","maxWidth":"100","alignment":"center","maxWidthPx":"0","aspectRatio":"auto","borderRadius":"20","imageAssetId":"289","overlayOpacity":"0","verticalOffset":"0","borderThickness":"1","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":""