ng","size":"75","effect":"none","newTab":"false","linkUrl":"","variant":"logo","alignment":"left","borderColor":"#c5a059","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"2","horizontalOffset":"0"}}],"alignment":"left","canonical":true,"isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"center","center":"left"},"cellShadow":{"left":"none","right":"none","center":"none"},"cellVAlign":{"left":"top","right":"top","center":"center"},"cellOpacity":{"left":"1","right":"1","center":"1"},"cellPadding":{"left":"0","right":"0","center":"0"},"marginBottom":"20","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false","center":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","savedSectionId":"saved_section_1781826409772_rcsh6r","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"center":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#d9e4ef","right":"#999999","center":"#ffffff"},"cellBorderStyle":{"left":"solid","right":"solid","center":"solid"},"cellBorderWidth":{"left":"0","right":"0","center":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"0","right":"14","center":"20"},"cellMobileHidden":{"left":"false","right":"false","center":"false"},"cellDesktopHidden":{"left":"false","right":"false","center":"false"},"cellVerticalMargin":{"left":"0","right":"0","center":"0"}},{"id":"348037cd-5139-48ea-86f2-3a03d32d4242","title":"Content Block 1","layout":"two-column","locked":false,"modules":[{"id":"module-ae640e95-5fca-45de-aaea-7ba97866a0d2","name":"","text":"<h1>Child Custody</h1><h2>Protecting Your Children. Preserving Your Rights. Building a Stable Future.</h2><p>At Marinoff &amp; Associates, P.C., we understand that few family law matters are more emotional or important than child custody. When your relationship with your child is at stake, the decisions made today can shape your family''s future for years to come. Whether you are going through a divorce, establishing parental responsibilities, modifying an existing order, or involved in a custody dispute, our experienced legal team is here to protect your rights and advocate for your child''s best interests.</p><p>We understand that every family is unique. Child custody cases often involve difficult questions about parenting time, decision-making responsibilities, school choices, healthcare, and maintaining meaningful relationships with both parents. Our attorneys take the time to understand your circumstances, listen to your concerns, and develop a legal strategy tailored to your family''s needs and goals.</p><h2>What Is Child Custody?</h2><p>Child custody, known in Colorado as the allocation of parental responsibilities, refers to the legal rights and responsibilities parents have regarding the care, upbringing, and decision-making for their children. Custody arrangements may include shared or primary parenting responsibilities and address important issues such as where a child lives, parenting time schedules, education, healthcare, and other major decisions. In every case, Colorado courts focus on one primary goal: protecting the best interests of the child and promoting their safety, stability, and well-being.</p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"86aa7632-5560-46ab-b6f7-d401d6ff04a3","name":"Justice","text":"","type":"image","column":"right","settings":{"alt":"Child custody lawyer Colorado","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1782506623910_ChatGPT_Image_Jun_26_2026_02_39_28_PM.png","size":"90","altText":"Image","linkUrl":"","imageUrl":"","maxWidth":"100","alignment":"center","maxWidthPx":"0","aspectRatio":"auto","borderRadius":"20","imageAssetId":"289","overlayOpacity":"0","verticalOffset":"0","borderThickness":"1","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#999999","right":"#999999"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"14","right":"14"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"section-1f91ac86-7404-42e9-a918-2e3386311456","title":"Content Block 2","layout":"two-column","locked":false,"modules":[{"id":"module-665ef090-ec37-4f92-b4b4-307af246259f","name":"","text":"","type":"image","column":"left","settings":{"alt":"Family law attorney Colorado","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1781876701068_Every_Family_Deserves.png","size":"90","effect":"none","newTab":"false","linkUrl":"","variant":"image","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}},{"id":"module-aeeafe39-cf70-4bfb-a824-7a8e28eb9f48","name":"","text":"<h1>Why Choose Marinoff &amp; Associates?</h1><h3>Experienced Child Custody Representation</h3><p>Our attorneys have extensive experience handling child custody matters through negotiation, mediation, and litigation. We understand the complexities of Colorado family law and work diligently to protect your parental rights and pursue the best possible outcome for your family.</p><h3>Child-Focused Solutions</h3><p>Every custody decision should support a child''s safety, stability, and well-being. We strive to develop parenting arrangements that foster healthy relationships and provide children with the structure and support they need to thrive.</p><h3>Compassionate Guidance</h3><p>Custody disputes can be emotionally overwhelming and stressful for parents and children alike. We provide thoughtful guidance, clear communication, and steady support throughout the process, helping you make informed decisions with confidence.</p><h3>Strong Advocacy for Parents and Families</h3><p>When important issues involving your children are at stake, you need an attorney who will advocate vigorously on your behalf. Whether negotiating an agreement or representing you in court, we are committed to protecting your rights, preserving your relationship with your children, and helping secure a brighter future for your family.</p>","type":"text","column":"right","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"transparent","right":"transparent"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"24","right":"24"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"3901f19a-b76d-4fc5-954b-d7fa01440538","title":"Content Block 3","layout":"two-column","locked":false,"modules":[{"id":"bddca40e-6861-4ab5-bdd6-3f428e1272af","name":"","text":"<h2>How We Can Help</h2><h3>Custody and Parenting Arrangements</h3><p>We help parents develop custody and parenting plans that promote stability, protect parental relationships, and serve the best interests of the child. Whether your situation involves joint decision-making, primary parenting responsibilities, or complex scheduling concerns, we work to create practical solutions tailored to your family''s needs.</p><h3>Parenting Time and Visitation</h3><p>Establishing a fair parenting schedule is essential for maintaining meaningful relationships between children and parents. We assist in creating clear, workable visitation and parenting plans that encourage consistency, minimize conflict, and provide children with a stable, loving environment.</p><h3>Modifications and Changing Circumstances</h3><p>Life changes, and custody arrangements sometimes need to change as well. If there has been a significant change in employment, living arrangements, relocation, or your child''s needs, we can help pursue modifications that better reflect your family''s current circumstances.</p><h3>Child Support and Financial Matters</h3><p>Custody issues often involve important financial considerations. We assist with child support matters, ensuring that support arrangements are fair, appropriate, and focused on meeting your child''s needs while considering each parent''s financial circumstances.</p><h3>Protecting Parental Rights</h3><p>When your relationship with your child is at stake, strong advocacy matters. If your parental rights are being challenged or concerns exist regarding a child''s safety and well-being, we work diligently to protect your rights and pursue solutions that prioritize your child''s best interests.</p><h3>Mediation and Alternative Dispute Resolution</h3><p>Not every custody matter requires litigation. When appropriate, we help parents resolve disputes through negotiation and mediation, often reducing conflict and allowing families to reach agreements more efficiently and collaboratively.</p><h2>Protecting Your Child''s Best Interests</h2><p>Child custody is not about winning or losing—it is about creating a safe, stable, and supportive environment where children can thrive. At Marinoff &amp; Associates, we are committed to helping families reach custody arrangements that protect children''s well-being while preserving meaningful parent-child relationships.</p><p>If you are facing a child custody matter, our experienced team is here to provide compassionate guidance, strategic advocacy, and the legal support you need to move forward with confidence and protect what matters most—your children and your future.</p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"7f613293-ea43-4504-b8f8-afd3f76ebfe5","name":"","text":"","type":"image","column":"right","settings":{"alt":"Colorado attorney","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/Stock_Photos/1781876826599_Best_Case_Scenario.png","size":"75","effect":"none","newTab":"false","linkUrl":"","variant":"image","alignment":"center","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":