ng","size":"75","effect":"none","newTab":"false","linkUrl":"","variant":"logo","alignment":"left","borderColor":"#c5a059","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"2","horizontalOffset":"0"}}],"alignment":"left","canonical":true,"isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"center","center":"left"},"cellShadow":{"left":"none","right":"none","center":"none"},"cellVAlign":{"left":"top","right":"top","center":"center"},"cellOpacity":{"left":"1","right":"1","center":"1"},"cellPadding":{"left":"0","right":"0","center":"0"},"marginBottom":"20","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false","center":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","savedSectionId":"saved_section_1781826409772_rcsh6r","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"center":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#d9e4ef","right":"#999999","center":"#ffffff"},"cellBorderStyle":{"left":"solid","right":"solid","center":"solid"},"cellBorderWidth":{"left":"0","right":"0","center":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"0","right":"14","center":"20"},"cellMobileHidden":{"left":"false","right":"false","center":"false"},"cellDesktopHidden":{"left":"false","right":"false","center":"false"},"cellVerticalMargin":{"left":"0","right":"0","center":"0"}},{"id":"348037cd-5139-48ea-86f2-3a03d32d4242","title":"Content Block 1","layout":"two-column","locked":false,"modules":[{"id":"module-ae640e95-5fca-45de-aaea-7ba97866a0d2","name":"","text":"<h1>Brandon Marinoff</h1><h2>Attorney &amp; Founder of Marinoff &amp; Associates, P.C.</h2><p>Brandon Marinoff is a Colorado attorney and the founder of Marinoff &amp; Associates, P.C., where he represents clients in the areas of criminal defense and immigration law. With decades of legal experience, Brandon has built his practice around helping individuals and families navigate some of the most difficult and important moments of their lives.</p><p>Mr. Marinoff graduated from St. John’s University in 1984 and earned his Juris Doctor from Touro Law School in 1991. Originally from Long Island, New York, he has lived and practiced in Colorado for many years, serving clients throughout the Denver metro area and across the state.</p><p>Before entering private practice, Brandon served as a Weld County prosecutor, an experience that gave him valuable insight into how criminal cases are investigated, charged, negotiated, and prosecuted. He also served as the former head of the Weld County Drug Task Force, giving him extensive experience with drug-related cases, law enforcement procedures, search and seizure issues, and complex criminal investigations. Today, that background helps him defend clients facing a wide range of criminal charges, including DUI/DWAI, drug offenses, traffic crimes, theft, assault, domestic violence, and serious felony allegations.</p><p>One of Brandon’s key strengths is his experience in both criminal defense and immigration law. These two areas often overlap, and a criminal charge can have serious immigration consequences for non-citizens, including detention, removal proceedings, inadmissibility, denial of citizenship, or difficulty obtaining lawful status. Brandon understands the importance of looking beyond the immediate case and developing legal strategies that consider a client’s rights, record, immigration status, family, and future.</p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"86aa7632-5560-46ab-b6f7-d401d6ff04a3","name":"Justice","text":"","type":"image","column":"right","settings":{"alt":"Justice","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1782670320823_B_marinoff_Bio.png","altText":"Image","linkUrl":"","imageUrl":"","maxWidth":"100","alignment":"center","maxWidthPx":"0","aspectRatio":"auto","borderRadius":"20","imageAssetId":"289","overlayOpacity":"0","verticalOffset":"0","borderThickness":"1","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#999999","right":"#999999"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"14","right":"14"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"section-1f91ac86-7404-42e9-a918-2e3386311456","title":"Content Block 2","layout":"two-column","locked":false,"modules":[{"id":"module-665ef090-ec37-4f92-b4b4-307af246259f","name":"","text":"","type":"image","column":"left","settings":{"alt":"","url":"https://lirp.cdn-website.com/03f0d32c/dms3rep/multi/opt/AdobeStock_1314941326-1920w.jpeg","size":"100","effect":"none","newTab":"false","linkUrl":"","variant":"image","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}},{"id":"module-aeeafe39-cf70-4bfb-a824-7a8e28eb9f48","name":"","text":"<p>At <strong>Marinoff &amp; Associates, P.C</strong>., Brandon also assists clients with immigration matters such as family petitions, U.S. citizenship, removal defense, asylum, waivers, U Visas, VAWA petitions, student visas, and business or investment visa matters.</p><p>Brandon is known for his straightforward communication, thorough preparation, and practical approach to legal problem-solving. He believes clients deserve honest advice, personal attention, and strong advocacy from the moment they contact the firm. Whether he is defending a client in criminal court, or guiding a family through an immigration matter, Brandon works to protect what matters most: his clients’ rights, families, freedom, status, and future.</p><p>Outside of the office, Brandon is a proud father of three. He is also an avid New York Mets fan and a lifelong tennis player. He played tennis at St. John’s University and continues to compete today.</p><p>Marinoff &amp; Associates, P.C. serves clients throughout Colorado, with offices in Westminster, Brighton, and Greeley.</p><p><strong>Your Rights. Your Family. Your Future. Our Commitment.</strong></p>","type":"text","co