ng","size":"75","effect":"none","newTab":"false","linkUrl":"","variant":"logo","alignment":"left","borderColor":"#c5a059","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"2","horizontalOffset":"0"}}],"alignment":"left","canonical":true,"isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"center","center":"left"},"cellShadow":{"left":"none","right":"none","center":"none"},"cellVAlign":{"left":"top","right":"top","center":"center"},"cellOpacity":{"left":"1","right":"1","center":"1"},"cellPadding":{"left":"0","right":"0","center":"0"},"marginBottom":"20","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false","center":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","savedSectionId":"saved_section_1781826409772_rcsh6r","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"center":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#d9e4ef","right":"#999999","center":"#ffffff"},"cellBorderStyle":{"left":"solid","right":"solid","center":"solid"},"cellBorderWidth":{"left":"0","right":"0","center":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"0","right":"14","center":"20"},"cellMobileHidden":{"left":"false","right":"false","center":"false"},"cellDesktopHidden":{"left":"false","right":"false","center":"false"},"cellVerticalMargin":{"left":"0","right":"0","center":"0"}},{"id":"348037cd-5139-48ea-86f2-3a03d32d4242","title":"Content Block 1","layout":"two-column","locked":false,"modules":[{"id":"module-ae640e95-5fca-45de-aaea-7ba97866a0d2","name":"","text":"<h1>Family Law</h1><h2>Compassionate Guidance. Strong Advocacy. Practical Solutions.</h2><p>Family law matters are deeply personal. They often involve the people you love most, the home you have built, your financial security, and your children’s future. Whether you are going through a divorce, fighting for custody, seeking child support, establishing paternity, pursuing adoption, or dealing with a difficult family conflict, you deserve legal guidance that is both compassionate and strategic.</p><p>At <strong>Marinoff &amp; Associates, P.C.</strong>, we understand that family law cases are not just legal disputes. They are life transitions. Our team is here to help you understand your rights, protect your interests, and move forward with clarity and confidence. We take the time to listen to your concerns, explain your options, and build a legal strategy focused on your goals, your family, and your future.</p><p>From the beginning of your case, our goal is to bring stability to an uncertain situation. Family law decisions can affect where your children live, how time is shared, how assets are divided, and how you move forward financially and emotionally.</p><p>At <strong>Marinoff &amp; Associates, P.C.</strong>, we approach every family law matter with careful preparation, honest communication, and a deep respect for what is at stake. Whether your case can be resolved through negotiation or requires strong courtroom advocacy, we are committed to helping you protect what matters most and create a path toward a more secure future.</p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"86aa7632-5560-46ab-b6f7-d401d6ff04a3","name":"Justice","text":"","type":"image","column":"right","settings":{"alt":"Colorado attorney","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1782501318637_Family_Law_Services_Colorado.png","size":"90","altText":"Image","linkUrl":"","imageUrl":"","maxWidth":"100","alignment":"center","maxWidthPx":"0","aspectRatio":"auto","borderRadius":"20","imageAssetId":"289","overlayOpacity":"0","verticalOffset":"0","borderThickness":"1","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#999999","right":"#999999"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"14","right":"14"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"section-1f91ac86-7404-42e9-a918-2e3386311456","title":"Content Block 2","layout":"two-column","locked":false,"modules":[{"id":"module-665ef090-ec37-4f92-b4b4-307af246259f","name":"","text":"","type":"image","column":"left","settings":{"alt":"Colorado divorce attorney","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1782502129471_Divorce_Lawyer_in_Colorado.png","size":"90","effect":"none","newTab":"false","linkUrl":"","variant":"image","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}},{"id":"module-aeeafe39-cf70-4bfb-a824-7a8e28eb9f48","name":"","text":"<h1>How Marinoff &amp; Associates Can Help</h1><p>Family law cases can be emotional, stressful, and complex. Decisions made during these cases can affect your children, finances, home, and long-term stability. Our firm provides steady guidance and strong representation through every stage of the process, whether your matter can be resolved through negotiation, mediation, or requires courtroom advocacy.</p><p>We assist clients with a wide range of family law matters, including:</p><h2>Divorce and Legal Separation</h2><p>Divorce can involve difficult decisions about property, finances, parenting time, support, and the future. We help clients navigate both contested and uncontested divorce cases with clear advice, careful preparation, and a focus on protecting what matters most.</p><h2>Child Custody and Parenting Time</h2><p>Few issues are more important than your relationship with your children. We work to protect your parental rights while helping create custody and parenting time arrangements that serve the best interests of your child.</p><h2>Child Support</h2><p>Child support issues require careful attention to income, expenses, parenting time, and the needs of the child. We help clients pursue fair and appropriate support arrangements, modifications, and enforcement when necessary.</p><h2>Spousal Support and Alimony</h2><p>Spousal support can have a major impact on your financial future. Whether you are seeking support or being asked to pay it, we help you understand your rights and pursue a fair outcome based on your circumstances.</p><h2>Property Division</h2><p>Dividing marital property can be one of the most complicated parts of divorce. We assist with issues involving homes, bank accounts, retirement accounts, debts, business interests, and other assets to help protect your financial stability.</p><h2>Domestic Violence and Protection Orders</h2><p>If you are facing abuse, threats, harassment, or an unsafe situation, we can help you understand your legal options and pursue protection. We also represent individuals who have been wrongly accused and need to defend their rights.</p><h2>Adoption and Paternity</h2><p>Family law is also about building families. We help clients with adoption matters, paternity actions, and legal steps that establish parental rights and responsibilities.</p><h2>Mediation and Alternative Dispute Resolution</h2><p>Not every family law case has to become a courtroom battle. When appropriate, we help clients explore mediation and settlement options designed to reduce conflict, save time, and reach practical agreements.</p>","type":"text","column":"right","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"transparent","right":"transparent"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"24","right":"24"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"b47aeb3b-2d12-43ac-a769-505638ffc69b","title":"Content Block 3","layout":"two-column","locked":false,"modules":[{"id":"ae03bfbe-9673-4bef-a255-60287afd7c2e","name":"","text":"<h1>Why Choose Marinoff &amp; Associates?</h1><h2>Experienced Family Law Representation</h2><p>Our legal team understands the family court system and the sensitive nature of family law disputes. We bring experience, preparation, and practical guidance to every case.</p><h2>Personalized Legal Strategies</h2><p>No two families are the same. We take the time to understand your circumstances, priorities, and concerns so we can create a strategy that fits your life and your goals.</p><h2>Compassionate Support</h2><p>Family law matters can be emotionally overwhelming. We provide calm, supportive guidance so you can make informed decisions during a difficult time.</p><h2>Strong Advocacy</h2><p>Whether we are negotiating a settlement, preparing for mediation, or representing you in court, we are committed to protecting your rights and pursuing the best possible outcome.</p><h2>Clear Communication</h2><p>You should never feel lost in your own case. We explain the process, answer your questions, and keep you informed so you know what to expect at every step.</p><h1>Protecting Your Family and Your Future</h1><p>At Marinoff &amp; Associates, we believe every family deserves stability, dignity, and hope. Our goal is to help you move through the legal process with confidence while protecting your rights, your children, your finances, and your future.</p><p>Family law challenges can feel overwhelming, but you do not have to face them alone. Whether you are preparing for divorce, working through custody issues, seeking protection, or building your family through adoption, our team is here to stand beside you with compassion, experience, and determination.</p><p><strong>Your family. Your future. Our commitment.</strong></p><p>Contact <strong>Marinoff &amp; Associates, P.C.</strong> today to schedule a consultation and learn how we can help you move forward.</p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"365efc93-4372-40eb-b250-68c4ad57b397","name":"","text":"","type":"image","column":"right","settings":{"alt":"Best divorce attorney Colorado","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/Stock_Photos/1781989833371_Every_Case_is_Personal.png","size":"90","effect":"none","newTab":"false","linkUrl":"","variant":"image","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity