ng","size":"75","effect":"none","newTab":"false","linkUrl":"","variant":"logo","alignment":"left","borderColor":"#c5a059","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"2","horizontalOffset":"0"}}],"alignment":"left","canonical":true,"isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"center","center":"left"},"cellShadow":{"left":"none","right":"none","center":"none"},"cellVAlign":{"left":"top","right":"top","center":"center"},"cellOpacity":{"left":"1","right":"1","center":"1"},"cellPadding":{"left":"0","right":"0","center":"0"},"marginBottom":"20","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false","center":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","savedSectionId":"saved_section_1781826409772_rcsh6r","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"center":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#d9e4ef","right":"#999999","center":"#ffffff"},"cellBorderStyle":{"left":"solid","right":"solid","center":"solid"},"cellBorderWidth":{"left":"0","right":"0","center":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"0","right":"14","center":"20"},"cellMobileHidden":{"left":"false","right":"false","center":"false"},"cellDesktopHidden":{"left":"false","right":"false","center":"false"},"cellVerticalMargin":{"left":"0","right":"0","center":"0"}},{"id":"348037cd-5139-48ea-86f2-3a03d32d4242","title":"Content Block 1","layout":"two-column","locked":false,"modules":[{"id":"module-ae640e95-5fca-45de-aaea-7ba97866a0d2","name":"","text":"<h1>Divorce</h1><h2>Compassionate Guidance. Strong Advocacy. A Path Forward.</h2><p>Divorce is more than the end of a marriage—it is a major life transition that can affect your family, finances, home, and future. The decisions made during a divorce can have lasting consequences for years to come, which is why having experienced legal representation is essential.</p><p>At <strong>Marinoff &amp; Associates, P.C.</strong>, we understand that divorce is often one of the most emotional and challenging experiences a person can face. Whether your divorce is amicable or highly contested, our team is committed to providing clear guidance, strong advocacy, and practical solutions tailored to your unique circumstances. We take the time to listen to your concerns, explain your legal options, and help you make informed decisions with confidence.</p><p>We believe divorce is not just about ending a marriage—it is about protecting what matters most and helping you build a stable foundation for the next chapter of your life. Our goal is to reduce uncertainty, protect your rights, and pursue solutions that support your long-term well-being and the well-being of your family.</p><h1>What Is Divorce?</h1><p>Divorce is the legal process of dissolving a marriage and resolving important issues such as property division, spousal support, child custody, parenting time, and child support. Some divorces can be resolved through agreement and cooperation, while others require negotiation, mediation, or litigation to achieve a fair outcome.</p><p>No matter the complexity of your case, Marinoff &amp; Associates is prepared to guide you through every stage of the process.</p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"86aa7632-5560-46ab-b6f7-d401d6ff04a3","name":"Justice","text":"","type":"image","column":"right","settings":{"alt":"Divorce attorney Colorado","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1782502479740_Divorce_Attorney_Colorado.png","size":"90","altText":"Image","linkUrl":"","imageUrl":"","maxWidth":"100","alignment":"center","maxWidthPx":"0","aspectRatio":"auto","borderRadius":"20","imageAssetId":"289","overlayOpacity":"0","verticalOffset":"0","borderThickness":"1","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#999999","right":"#999999"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"14","right":"14"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"section-1f91ac86-7404-42e9-a918-2e3386311456","title":"Content Block 2","layout":"two-column","locked":false,"modules":[{"id":"module-665ef090-ec37-4f92-b4b4-307af246259f","name":"","text":"","type":"image","column":"left","settings":{"alt":"Divorce attorney consultation","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/Stock_Photos/1781877062756_Every_Case_Has_Two_Sides.png","size":"90","effect":"none","newTab":"false","linkUrl":"","variant":"image","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}},{"id":"module-aeeafe39-cf70-4bfb-a824-7a8e28eb9f48","name":"","text":"<h2>Why Choose Marinoff &amp; Associates?</h2><h3>Experienced Divorce Attorneys</h3><p>Our legal team has extensive experience handling both contested and uncontested divorces throughout Colorado. We understand the legal, financial, and emotional challenges involved and work diligently to protect your interests.</p><h3>Personalized Legal Strategies</h3><p>Every family is different, and every divorce presents unique circumstances. We develop legal strategies tailored to your specific goals, priorities, and concerns.</p><h3>Compassionate Support</h3><p>We understand that divorce can be emotionally overwhelming. We provide honest guidance, clear communication, and steady support so you never feel alone during the process.</p><h3>Strong Advocacy</h3><p>Whether negotiating a settlement or litigating in court, we are committed to protecting your rights, your financial future, and your relationship with your children.</p><p></p>","type":"text","column":"right","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"transparent","right":"transparent"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"24","right":"24"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"a209a5ee-4600-46b4-aba2-d568c8404846","title":"Content Block 3","layout":"two-column","locked":false,"modules":[{"id":"31801026-e38d-4ece-a516-96f926fe903d","name":"","text":"<h2>How We Can Help</h2><h3>Contested and Uncontested Divorce</h3><p>We guide clients through both cooperative and high-conflict divorce proceedings, helping them achieve the best possible resolution.</p><h3>Property Division</h3><p>We work to ensure marital assets and debts are divided fairly while protecting your financial interests and future security.</p><h3>Spousal Support (Alimony)</h3><p>Whether you are seeking support or responding to a request, we advocate for reasonable and equitable outcomes.</p><h3>Child Custody and Child Support</h3><p>Nothing is more important than your children. We work to protect parental rights and pursue custody and support arrangements that serve your children''s best interests.</p><h3>Mediation and Alternative Dispute Resolution</h3><p>When possible, we help clients resolve disputes through negotiation and mediation, often reducing conflict, expense, and stress.</p><h3>Post-Divorce Modifications</h3><p>Life circumstances change. We assist with modifications involving custody, parenting time, child support, and spousal maintenance when existing orders no longer reflect current realities.</p><h2>Protecting Your Rights and Your Future</h2><p>Divorce can feel overwhelming, but you do not have to face it alone. At Marinoff &amp; Associates, P.C., we are committed to helping individuals and families navigate divorce with confidence, dignity, and peace of mind. We work tirelessly to protect your rights, preserve your financial stability, and position you for a stronger future.</p><p>If you are considering divorce or have been served with divorce papers, contact Marinoff &amp; Associates today. We are here to stand beside you, guide you through the process, and help you move forward with confidence.</p><p><strong>Protecting Your Rights. Preserving What Matters. Helping You Build Your Next Chapter.</strong></p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"a987b758-a5a3-492f-b2a1-e6810731e71e","name":"","text":"","type":"image","column":"right","settings":{"alt":"Colorado criminal defense attorney","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/Stock_Photos/1781989849561_Brandon_Testimonial.png","size":"75","effect":"none","newTab":"false","linkUrl":"","variant":"image","alignment":"center","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","backgroun