ng","size":"75","effect":"none","newTab":"false","linkUrl":"","variant":"logo","alignment":"left","borderColor":"#c5a059","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"2","horizontalOffset":"0"}}],"alignment":"left","canonical":true,"isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"center","center":"left"},"cellShadow":{"left":"none","right":"none","center":"none"},"cellVAlign":{"left":"top","right":"top","center":"center"},"cellOpacity":{"left":"1","right":"1","center":"1"},"cellPadding":{"left":"0","right":"0","center":"0"},"marginBottom":"20","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false","center":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","savedSectionId":"saved_section_1781826409772_rcsh6r","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"center":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#d9e4ef","right":"#999999","center":"#ffffff"},"cellBorderStyle":{"left":"solid","right":"solid","center":"solid"},"cellBorderWidth":{"left":"0","right":"0","center":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"0","right":"14","center":"20"},"cellMobileHidden":{"left":"false","right":"false","center":"false"},"cellDesktopHidden":{"left":"false","right":"false","center":"false"},"cellVerticalMargin":{"left":"0","right":"0","center":"0"}},{"id":"348037cd-5139-48ea-86f2-3a03d32d4242","title":"Content Block 1","layout":"two-column","locked":false,"modules":[{"id":"module-ae640e95-5fca-45de-aaea-7ba97866a0d2","name":"","text":"<h1>Separation</h1><h2>Guidance, Protection, and Clarity During Life''s Transitions</h2><h3>Understanding Separation</h3><p>Choosing to separate from your spouse can be one of the most emotional and uncertain decisions you will ever make. Separation often raises difficult questions about your children, finances, home, and future. Whether you are considering a trial separation to evaluate your relationship or pursuing a formal legal separation, having experienced legal guidance can provide clarity and peace of mind.</p><p>Unlike divorce, separation does not legally end a marriage. However, it can establish important arrangements regarding child custody, parenting time, support obligations, property division, and financial responsibilities. A well-structured separation agreement can provide stability and protect your interests while giving you time and space to determine the best path forward.</p><p>For many couples, separation serves as a period of transition and reflection. It allows spouses to address important issues while reducing uncertainty and creating a framework for moving forward. Decisions made during this stage can have significant and lasting effects on your financial security, parental rights, and future opportunities. Understanding your rights and obligations early in the process can help you make informed decisions and avoid unnecessary disputes down the road.</p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"86aa7632-5560-46ab-b6f7-d401d6ff04a3","name":"Justice","text":"","type":"image","column":"right","settings":{"alt":"What is legal separation","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1782504942563_ChatGPT_Image_Jun_26_2026_01_36_14_PM.png","size":"90","altText":"Image","linkUrl":"","imageUrl":"","maxWidth":"100","alignment":"center","maxWidthPx":"0","aspectRatio":"auto","borderRadius":"20","imageAssetId":"289","overlayOpacity":"0","verticalOffset":"0","borderThickness":"1","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#999999","right":"#999999"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"14","right":"14"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"section-1f91ac86-7404-42e9-a918-2e3386311456","title":"Content Block 2","layout":"two-column","locked":false,"modules":[{"id":"module-665ef090-ec37-4f92-b4b4-307af246259f","name":"","text":"","type":"image","column":"left","settings":{"alt":"How to file for divorce","url":"https://irp.cdn-website.com/03f0d32c/dms3rep/multi/pexels-photo-4098231.jpeg","size":"90","effect":"none","newTab":"false","linkUrl":"","variant":"image","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}},{"id":"module-aeeafe39-cf70-4bfb-a824-7a8e28eb9f48","name":"","text":"<h3>How Marinoff &amp; Associates Can Help</h3><p>At Marinoff &amp; Associates, P.C., we understand that every family situation is unique. We take the time to listen to your concerns, explain your legal options, and develop solutions tailored to your specific needs and goals. Our team is committed to helping you make informed decisions with confidence and reducing uncertainty during this transitional period.</p><p>We assist clients with:</p><ul><li><p>Legal Separation Agreements</p></li><li><p>Trial Separation Planning and Guidance</p></li><li><p>Child Custody and Parenting Arrangements</p></li><li><p>Child Support and Spousal Maintenance</p></li><li><p>Property and Debt Division</p></li><li><p>Modifications of Existing Agreements</p></li></ul><p>Separation often involves complex legal, financial, and emotional considerations. Our attorneys carefully evaluate every aspect of your circumstances and work to protect your rights while seeking practical solutions that support your long-term interests. Whether your situation can be resolved through cooperation and negotiation or requires court intervention, we are prepared to advocate for your interests and guide you through every stage of the process with compassion and professionalism.</p>","type":"text","column":"right","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"transparent","right":"transparent"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"24","right":"24"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"23d6beb2-d6e6-4e5e-9f59-d5135dc45889","title":"Content Block 3","layout":"two-column","locked":false,"modules":[{"id":"beea7b76-9b6f-4964-9167-b024f5a7c238","name":"","text":"<h3>Protecting Your Rights and Moving Forward</h3><p>Although separation does not dissolve a marriage, it can significantly impact your legal rights, financial security, and family relationships. The decisions made during this period can affect your future for years to come. Having experienced legal representation can help ensure that your interests are protected and that important matters are addressed carefully and fairly.</p><p>At <strong>Marinoff &amp; Associates, P.C.</strong>, we believe that separation is not simply about living apart—it is about creating stability during a period of change and helping you move forward with confidence. Our goal is to help you protect what matters most, minimize conflict whenever possible, and position you for a stronger future. We provide steady guidance, clear communication, and dedicated advocacy so that you can focus on your family and your next chapter while we handle the legal complexities.</p><p>If you are considering a separation or have already begun the process, our team is here to stand beside you, answer your questions, and help you navigate this transition with confidence and peace of mind.</p><p><strong>Protecting What Matters. Creating Stability. Helping You Move Forward with Confidence.</strong></p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"295e1c64-6e4c-47ad-a719-4fca74b0c6a4","name":"","text":"","type":"image","column":"right","settings":{"alt":"Colorado divorce attorney","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/Stock_Photos/1781876826599_Best_Case_Scenario.png","size":"75","effect":"none","newTab":"false","linkUrl":"","variant":"image","alignment":"center","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","i