ng","size":"75","effect":"none","newTab":"false","linkUrl":"","variant":"logo","alignment":"left","borderColor":"#c5a059","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"2","horizontalOffset":"0"}}],"alignment":"left","canonical":true,"isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"center","center":"left"},"cellShadow":{"left":"none","right":"none","center":"none"},"cellVAlign":{"left":"top","right":"top","center":"center"},"cellOpacity":{"left":"1","right":"1","center":"1"},"cellPadding":{"left":"0","right":"0","center":"0"},"marginBottom":"20","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false","center":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","savedSectionId":"saved_section_1781826409772_rcsh6r","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"center":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#d9e4ef","right":"#999999","center":"#ffffff"},"cellBorderStyle":{"left":"solid","right":"solid","center":"solid"},"cellBorderWidth":{"left":"0","right":"0","center":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"0","right":"14","center":"20"},"cellMobileHidden":{"left":"false","right":"false","center":"false"},"cellDesktopHidden":{"left":"false","right":"false","center":"false"},"cellVerticalMargin":{"left":"0","right":"0","center":"0"}},{"id":"348037cd-5139-48ea-86f2-3a03d32d4242","title":"Content Block 1","layout":"two-column","locked":false,"modules":[{"id":"module-ae640e95-5fca-45de-aaea-7ba97866a0d2","name":"","text":"<h1>VAWA</h1><p>At Marinoff &amp; Associates, we recognize the deep challenges and emotional toll that victims of domestic violence or abuse often face. If you have suffered abuse at the hands of a U.S. citizen or lawful permanent resident spouse, parent, or child, you may be eligible for protection under the <strong>Violence Against Women Act (VAWA)</strong>. Our legal team is here to guide you through the VAWA self-petition process, providing the support and expertise you need to escape abusive situations and secure a path to lawful status in the United States.</p><p></p><h2 style=\"font-size: 30px; line-height: 2; color: rgb(33, 76, 113);\"><strong>What Is VAWA?</strong></h2><p style=\"font-size: 1.1rem; line-height: 1.6; color: rgb(71, 85, 105);\">The Violence Against Women Act (VAWA) is a federal law that allows victims of domestic violence, abuse, or extreme cruelty to self-petition for legal immigration status without the involvement or consent of their abuser. VAWA is designed to help those who may be at risk of deportation due to their abusive relationship or other immigration violations but are afraid or unable to rely on their abuser to help them navigate the immigration process. Though originally intended for women, VAWA protections also apply to men and children who are victims of abuse.</p><h2 style=\"font-size: 30px; line-height: 2; color: rgb(33, 76, 113);\"><strong>Personal Service. Trusted Legal Guidance</strong></h2><p style=\"font-size: 1.1rem; line-height: 1.6; color: rgb(71, 85, 105);\">At <strong>Marinoff &amp; Associates, P.C.</strong>, we understand that every client''s story is unique. We approach every VAWA case with compassion, discretion, and respect, taking the time to understand your circumstances and build the strongest possible petition on your behalf. From gathering supporting documentation and preparing detailed evidence to communicating with immigration authorities, our goal is to help you move forward with confidence toward safety, stability, work authorization when available, and, ultimately, lawful permanent residence.</p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"86aa7632-5560-46ab-b6f7-d401d6ff04a3","name":"VAWA","text":"","type":"image","column":"right","settings":{"alt":"Violence Against Women Act attorney","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1782657708490_ChatGPT_Image_Jun_28_2026_08_41_21_AM.png","size":"90","altText":"Image","linkUrl":"","imageUrl":"","maxWidth":"100","alignment":"center","maxWidthPx":"0","aspectRatio":"auto","borderRadius":"20","imageAssetId":"289","overlayOpacity":"0","verticalOffset":"0","borderThickness":"1","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#999999","right":"#999999"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"14","right":"14"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"section-1f91ac86-7404-42e9-a918-2e3386311456","title":"Content Block 2","layout":"two-column","locked":false,"modules":[{"id":"module-665ef090-ec37-4f92-b4b4-307af246259f","name":"","text":"","type":"image","column":"left","settings":{"alt":"VAWA immigration lawyer","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/Stock_Photos/1781877192487_Justice.png","size":"90","effect":"none","newTab":"false","linkUrl":"","variant":"image","alignment":"center","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}},{"id":"module-aeeafe39-cf70-4bfb-a824-7a8e28eb9f48","name":"","text":"<h2><strong>Why Choose Marinoff &amp; Associates?</strong></h2><ol><li><p><strong>Experienced VAWA Attorneys: </strong>Our legal team specializes in VAWA cases and understands the complexities involved in securing immigration relief for victims of abuse. We are committed to helping you navigate the legal process and protect your safety and future.</p></li><li><p><strong>Compassionate and Confidential Support: </strong>We understand the sensitive nature of domestic violence cases and approach each case with care, confidentiality, and understanding. Your safety and well-being are our top priority throughout the entire process.</p></li><li><p><strong>Guidance Through the VAWA Process: </strong>The VAWA self-petitioning process can be challenging. We are here to ensure that you understand your rights, gather the required evidence, and submit a compelling application to increase your chances of success.</p></li><li><p><strong>Holistic Approach to Your Case: </strong>We not only assist with the VAWA petition but also help you explore other avenues for legal relief, such as work authorization, adjustment of status, and possible family member petitions.</p></li></ol><p></p>","type":"text","column":"right","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"transparent","right":"transparent"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"24","right":"24"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"3331971f-361b-43fd-ae83-4acd7b5148ef","title":"Content Block 3","layout":"two-column","locked":false,"modules":[{"id":"03cce3a1-fbd9-49b9-b78f-1866d18bec33","name":"","text":"<h2><strong>How We Can Help:</strong></h2><ul><li><p><strong>Eligibility Evaluation: </strong>We will evaluate your situation to determine whether you meet the eligibility requirements for a VAWA self-petition. To qualify, you must demonstrate that you have experienced abuse or extreme cruelty by a U.S. citizen or lawful permanent resident spouse, parent, or child, and that you have lived with the abuser.</p></li><li><p><strong>Filing the VAWA Self-Petition (Form I-360): </strong>Our team will assist you in preparing and filing the VAWA self-petition, ensuring that all the necessary documentation is included and the petition is complete. We will help you collect evidence of the abuse and your relationship with the abuser, including police reports, medical records, affidavits, and other supporting materials.</p></li><li><p><strong>Work Authorization (Form I-765): </strong>If your VAWA self-petition is approved, you may be eligible to apply for work authorization while your petition is pending. We will assist you with the application and ensure that you ca<strong>n legally support yourself during the process.</strong></p></li><li><p><strong>Adjustment of Status (Form I-485): </strong>If your VAWA petition is approved and you are eligible for a green card, we will guide you through the process of applying for adjustment of status to become a lawful permanent resident.</p></li><li><p><strong>Protecting Your Family: </strong>If you have children who have also experienced abuse or are at risk of harm, we can help you include them in your VAWA petition and secure protection for them as well.</p></li><li><p><strong>Appeals and Denials: </strong>If your VAWA self-petition is denied, we will explore all options for appealing the decision or re-filing your case, ensuring that you have the best chance of achieving a positive outcome.</p></li><li><p><strong>Emergency Legal Services: </strong>If you are in immediate danger or need urgent legal intervention, we can assist you with finding emergency protection orders, legal separation, or other emergency services to protect your safety while your VAWA case is pending.</p></li></ul><h2><strong><br>Giving You a Path to Safety and Legal Status</strong></h2><p><strong><br></strong>VAWA is designed to protect individuals who are trapped in abusive relationships and provide them with the opportunity to remain in the U.S. without fear of retaliation from an abuser. At Marinoff &amp; Associates, we are committed to helping you secure your safety, gain legal status, and rebuild your life free from abuse.</p><p><br>If you are a victim of abuse and need assistance with a VAWA self-petition, contact Marinoff &amp; Associates today. Our experienced attorneys will guide you through the VAWA process, protect your rights, and provide the support you need during this difficult time.<br></p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"7da58c12-2aec-4d70-880e-7fd733cd1efe","name":"","text":"","type":"image","column":"right","settings":{"alt":"Westminster immigration attorney","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1781876744315_Greatest_Attorney.png","size":"90","effect":"none","newTab":"false","linkUrl":"","variant":"image","alignment":"center","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBott