ng","size":"75","effect":"none","newTab":"false","linkUrl":"","variant":"logo","alignment":"left","borderColor":"#c5a059","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"2","horizontalOffset":"0"}}],"alignment":"left","canonical":true,"isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"center","center":"left"},"cellShadow":{"left":"none","right":"none","center":"none"},"cellVAlign":{"left":"top","right":"top","center":"center"},"cellOpacity":{"left":"1","right":"1","center":"1"},"cellPadding":{"left":"0","right":"0","center":"0"},"marginBottom":"20","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false","center":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","savedSectionId":"saved_section_1781826409772_rcsh6r","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"center":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#d9e4ef","right":"#999999","center":"#ffffff"},"cellBorderStyle":{"left":"solid","right":"solid","center":"solid"},"cellBorderWidth":{"left":"0","right":"0","center":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"0","right":"14","center":"20"},"cellMobileHidden":{"left":"false","right":"false","center":"false"},"cellDesktopHidden":{"left":"false","right":"false","center":"false"},"cellVerticalMargin":{"left":"0","right":"0","center":"0"}},{"id":"348037cd-5139-48ea-86f2-3a03d32d4242","title":"Content Block 1","layout":"two-column","locked":false,"modules":[{"id":"module-ae640e95-5fca-45de-aaea-7ba97866a0d2","name":"","text":"<h1>Family Petitions</h1><h2>Reuniting Families. Building Futures. Navigating Immigration with Confidence.</h2><p>At <strong>Marinoff &amp; Associates, P.C.</strong>, we understand that nothing is more important than keeping families together. Family-based immigration allows U.S. citizens and lawful permanent residents to sponsor certain relatives for lawful immigration status, creating opportunities for loved ones to reunite and build a future together in the United States. While the immigration process can be complex, our experienced legal team is committed to helping families navigate every step with confidence, compassion, and personalized legal guidance.</p><p>Whether you are petitioning for your spouse, child, parent, fiancé(e), or another eligible family member, we work diligently to ensure your petition is prepared accurately, supported with the proper documentation, and submitted in compliance with all immigration requirements. Every family''s situation is unique, and we develop customized legal strategies designed to minimize delays and maximize your opportunity for success.</p><p></p><h1>What Are Family-Based Immigration Petitions?</h1><p>Family petitions allow qualifying U.S. citizens and lawful permanent residents (Green Card holders) to sponsor eligible relatives for immigration benefits. Depending on the relationship and immigration category, the process may lead to permanent residency (Green Card status), adjustment of status within the United States, or immigrant visa processing through a U.S. consulate abroad.</p><p>Family immigration laws involve detailed eligibility requirements, extensive documentation, government interviews, and strict filing procedures. Missing information or filing errors can result in significant delays or denials. Having experienced legal guidance throughout the process can help protect your interests and keep your case moving forward.</p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"86aa7632-5560-46ab-b6f7-d401d6ff04a3","name":"Family Petition","text":"","type":"image","column":"right","settings":{"alt":"Family petition attorney","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1782659058657_Family_Petitions.png","size":"90","altText":"Image","linkUrl":"","imageUrl":"","maxWidth":"100","alignment":"center","maxWidthPx":"0","aspectRatio":"auto","borderRadius":"20","imageAssetId":"289","overlayOpacity":"0","verticalOffset":"0","borderThickness":"1","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#999999","right":"#999999"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"14","right":"14"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"section-1f91ac86-7404-42e9-a918-2e3386311456","title":"Content Block 2","layout":"two-column","locked":false,"modules":[{"id":"module-665ef090-ec37-4f92-b4b4-307af246259f","name":"","text":"","type":"image","column":"left","settings":{"alt":"Family petition immigration lawyer","url":"https://irp.cdn-website.com/03f0d32c/dms3rep/multi/pexels-photo-1456951.jpeg","size":"90","effect":"none","newTab":"false","linkUrl":"","variant":"image","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}},{"id":"module-aeeafe39-cf70-4bfb-a824-7a8e28eb9f48","name":"","text":"<h1><strong>Why Choose Marinoff &amp; Associates?</strong></h1><p>Family immigration is about more than legal forms—it is about reuniting loved ones and creating a secure future together. At Marinoff &amp; Associates, P.C., we understand how important these cases are and provide personalized legal guidance tailored to your family''s unique circumstances. We take the time to understand your goals, explain the immigration process clearly, and develop a strategy designed to help you move forward with confidence.</p><p>Whether you are sponsoring a spouse, parent, child, or fiancé(e), or pursuing adjustment of status or consular processing, our experienced team is committed to protecting your interests every step of the way. We prepare thorough applications, address potential challenges, and provide responsive communication and compassionate support while working toward the best possible outcome for you and your family.</p><ol><li><p><strong>Expert Guidance on Family Petitions: </strong>Our attorneys are well-versed in the family immigration process and have helped many individuals successfully petition for their loved ones. We will ensure that you understand every step of the process and avoid common pitfalls that can delay or derail your case.</p></li><li><p><strong>Personalized Legal Solutions: </strong>We recognize that each family situation is unique. We will work closely with you to assess your specific case, determine eligibility, and help you navigate the complexities of family-based immigration.</p></li><li><p><strong>Compassionate Support: </strong>Reuniting with family members is a deeply personal and emotional experience. We offer compassionate support, treating your family’s immigration needs with the care and respect they deserve.</p></li><li><p><strong>Comprehensive Services: </strong>Whether you are petitioning for your spouse, parent, child, sibling, or other relatives, we provide comprehensive services, ensuring all necessary forms are completed accurately and filed in a timely manner.</p></li></ol><p></p>","type":"text","column":"right","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"transparent","right":"transparent"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"24","right":"24"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"ac16a110-f3a7-4ad7-a18b-481a3eacbba5","title":"Content Block 2","layout":"two-column","locked":false,"modules":[{"id":"016f3e99-bddc-4ffe-b328-84aa1fcc2a2f","name":"","text":"<h2><strong>How We Can Help:</strong></h2><ul><li><p><strong>Petitioning for a Spouse (Form I-130): </strong>If you are a U.S. citizen or lawful permanent resident, we can help you petition for your spouse to join you in the U.S. We’ll ensure that your petition is complete and that you meet the necessary requirements for your spouse’s green card application.</p></li><li><p><strong>Petitioning for Children (Form I-130): </strong>We can assist in petitioning for your children, whether they are biological, stepchildren, or adopted children, to join you in the U.S. or adjust their status. This includes both minor children and adult children who meet specific criteria.</p></li><li><p><strong>Petitioning for Parents (Form I-130): </strong>If you are a U.S. citizen, we can help you petition for your parents to come to the U.S. and receive permanent residency. This process is typically faster for U.S. citizens and has no annual cap, making it one of the most straightforward family petitions.</p></li><li><p><strong>Petitioning for Siblings (Form I-130): </strong>As a U.S. citizen, you may also petition for your siblings to join you in the U.S. This process is more involved and may take several years, depending on visa availability, but we will guide you through every step.</p></li><li><p><strong>Adjustment of Status: </strong>If your family member is already in the U.S. and eligible for a green card, we can assist with the adjustment of status process, allowing them to apply for lawful permanent residency without leaving the U.S.</p></li><li><p><strong>Consular Processing: </strong>If your family member is outside the U.S., we will guide them through consular processing, which involves applying for a visa at a U.S. consulate in their home country. We will ensure they understand the necessary steps and requirements for a successful visa application.</p></li><li><p><strong>Expedited Petitions: </strong>In certain situations, such as for spouses or minor children of U.S. citizens, we can explore options for expedited processing to reduce the time it takes to bring your loved ones to the U.S.</p></li><li><p><strong>Waivers of Inadmissibility:</strong> If your family member is facing inadmissibility issues, such as unlawful presence or a criminal record, we can help you apply for the necessary waivers to overcome these obstacles and move forward with the family petition.</p></li><li><p><strong>Legal Representation in Interviews and Appeals:</strong> If your family member’s petition is denied, we can help you appeal the decision or represent you in interviews to resolve any issues that may arise during the process.</p></li></ul><p></p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"e474aa59-4fab-43e2-9e43-3818e3f10c30","name":"","text":"","type":"image","column":"right","settings":{"alt":"Relative petition immigration","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1782659194031_Positive_Testimonial.png","size":"90","effect":"none","newTab":"false","linkUrl":"","variant":"image","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"transparent","right":"transparent"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"24","right":"24"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"711dddf6-85bc-4655-aa73-791a09b9b2b6","title":"Content Block 2","layout":"two-column","locked":false,"modules":[{"id":"cbe39e04-a060-46d9-89f7-dfafc1552225","name":"","text":"<h2><strong>Bringing Your Family Together</strong></h2><p><strong><br></strong>Family-based immigration is a crucial part of U.S. immigration law, and we are committed to helping you reunite with your loved ones. Whether you are petitioning for a spouse, child, parent, or sibling, Marinoff &amp; Associates will provide the expert legal representation and personalized service you need to navigate the family petition process successfully.</p><p>If you are ready to start the family petition process or have questions about your specific situation, contact Marinoff &amp; Associates today. Our dedicated attorneys are here to help you bring your family together and ensure that your immigration journey is as smooth and successful as possible.<strong><br></strong></p>","type":"text","column":"right","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"ca6f3133-b07d-47a7-864a-7e30c0859559","name":"","text":"","type":"image","column":"left","settings":{"alt":"Colorado immigration attorney","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1782659402128_Family_Petitions_-_Immigration_Law.webp","size":"90","effect":"none","newTab":"false","linkUrl":"","variant":"image","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"i