ng","size":"75","effect":"none","newTab":"false","linkUrl":"","variant":"logo","alignment":"left","borderColor":"#c5a059","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"2","horizontalOffset":"0"}}],"alignment":"left","canonical":true,"isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"center","center":"left"},"cellShadow":{"left":"none","right":"none","center":"none"},"cellVAlign":{"left":"top","right":"top","center":"center"},"cellOpacity":{"left":"1","right":"1","center":"1"},"cellPadding":{"left":"0","right":"0","center":"0"},"marginBottom":"20","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false","center":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","savedSectionId":"saved_section_1781826409772_rcsh6r","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"center":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#d9e4ef","right":"#999999","center":"#ffffff"},"cellBorderStyle":{"left":"solid","right":"solid","center":"solid"},"cellBorderWidth":{"left":"0","right":"0","center":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"0","right":"14","center":"20"},"cellMobileHidden":{"left":"false","right":"false","center":"false"},"cellDesktopHidden":{"left":"false","right":"false","center":"false"},"cellVerticalMargin":{"left":"0","right":"0","center":"0"}},{"id":"348037cd-5139-48ea-86f2-3a03d32d4242","title":"Content Block 1","layout":"two-column","locked":false,"modules":[{"id":"module-ae640e95-5fca-45de-aaea-7ba97866a0d2","name":"","text":"<h1>Immigration Law</h1><h2>Protecting Families. Creating Opportunities. Building Futures.</h2><p>Immigration is more than a legal process—it is about people, families, dreams, and opportunities. For many individuals and families, immigration represents the hope of a better future, access to education, career advancement, reunification with loved ones, and the chance to build a life in the United States. However, navigating the U.S. immigration system can be overwhelming, complicated, and emotionally stressful.</p><p>At <strong>Marinoff &amp; Associates, P.C.</strong>, we understand that immigration matters often involve some of the most important decisions a person will ever make. Whether you are seeking a visa, pursuing lawful permanent residency, applying for citizenship, petitioning for family members, or facing an immigration issue connected to a criminal matter, our experienced legal team is here to guide you every step of the way.</p><p>We believe every client deserves clear answers, personalized guidance, and dedicated advocacy. Immigration laws and policies frequently change, and even a small mistake or delay can have significant consequences. That is why we take the time to understand your goals, explain your options, and develop legal strategies tailored to your unique circumstances.</p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"86aa7632-5560-46ab-b6f7-d401d6ff04a3","name":"Justice","text":"","type":"image","column":"right","settings":{"alt":"Colorado immigration attorney helping families","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/Stock_Photos/1781877027784_Immigration_-_Personal_Touch.png","size":"90","altText":"Image","linkUrl":"","imageUrl":"","maxWidth":"100","alignment":"center","maxWidthPx":"0","aspectRatio":"auto","borderRadius":"20","imageAssetId":"289","overlayOpacity":"0","verticalOffset":"0","borderThickness":"1","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#999999","right":"#999999"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"14","right":"14"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"section-1f91ac86-7404-42e9-a918-2e3386311456","title":"Content Block 2","layout":"two-column","locked":false,"modules":[{"id":"module-aeeafe39-cf70-4bfb-a824-7a8e28eb9f48","name":"","text":"<h1>Experience Where Immigration and Criminal Law Intersect</h1><p>One of the qualities that makes Marinoff &amp; Associates unique is our experience in both Immigration Law and Criminal Defense. In many cases, these areas of law overlap. A criminal charge or conviction can affect a person''s immigration status, ability to obtain lawful residency, eligibility for citizenship, or even their ability to remain in the United States.</p><p>Successfully handling these situations requires careful planning and a comprehensive legal strategy that considers both the immediate legal issue and its long-term immigration consequences. Our team understands these complexities and works diligently to protect our clients'' rights, opportunities, and futures.</p><p></p><h2>A Personalized Approach to Immigration Matters</h2><p>No two immigration journeys are alike. Every client comes to us with different goals, challenges, and circumstances. Some are pursuing educational opportunities, others are seeking to reunite with family members, and many are working toward becoming permanent residents or U.S. citizens.</p><p>At Marinoff &amp; Associates, we take a personalized approach to every case. We listen carefully to your concerns, communicate clearly throughout the process, and remain committed to helping you make informed decisions with confidence. Our goal is to provide knowledgeable legal guidance while making the immigration process as smooth and understandable as possible.</p>","type":"text","column":"right","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"module-665ef090-ec37-4f92-b4b4-307af246259f","name":"","text":"","type":"image","column":"left","settings":{"alt":"Experienced immigration lawyer in Colorado","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1782582196540_Expereinced_Immigration_Attorneys.png","size":"90","effect":"none","newTab":"false","linkUrl":"","variant":"image","alignment":"center","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"transparent","right":"transparent"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"24","right":"24"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"7a3d2f9f-c5de-434f-897b-169c6a74d4c5","title":"Content Block 3","layout":"two-column","locked":false,"modules":[{"id":"51290b02-86a7-4ad1-a1c5-1c2b5b435590","name":"","text":"<h2>How Marinoff &amp; Associates Can Help</h2><p>Our firm provides comprehensive immigration representation for individuals and families throughout Colorado and beyond. We assist clients with a wide range of immigration matters, including:</p><ul><li><p><strong>Visa Applications and Work Permits: </strong>Whether you are applying for a student visa, work visa, tourist visa, or family-based visa, we can help you understand the requirements and complete the necessary paperwork to ensure your application is successful.</p></li><li><p><strong>Green Cards and Permanent Residency: </strong>We assist clients in obtaining lawful permanent resident status (a green card) through family, employment, or other categories. We guide you through the process and ensure that all documentation is completed accurately.</p></li><li><p><strong>Citizenship and Naturalization: </strong>If you are looking to become a U.S. citizen, we can assist with the naturalization process, including meeting eligibility requirements, preparing your application, and helping you prepare for the citizenship interview.</p></li><li><p><strong>Family-Based Immigration: </strong>We help families reunite through family-based immigration petitions, including spousal visas, fiancé visas, and family preference visas.</p></li><li><p><strong>Asylum and Refugee Status: </strong>If you are fleeing persecution or facing danger in your home country, we can assist you in applying for asylum or refugee status, ensuring your case is presented effectively and timely.</p></li><li><p><strong>Deportation Defense and Removal Proceedings: </strong>If you are facing deportation or removal proceedings, our team will work to defend your case, exploring all avenues of relief and fighting to keep you in the United States.</p></li><li><p><strong>Immigration Appeals:</strong> If your immigration application has been denied, we can help you file an appeal and fight for a reversal of the decision, presenting new evidence or arguments to support your case.</p></li><li><p><strong>Immigration Compliance and Employer Services: </strong>We offer advice to employers on compliance with immigration laws, helping businesses understand visa requirements for foreign workers and ensuring proper documentation is maintained.</p></li></ul><h2><strong><br></strong>Building a Better Future Together</h2><p>Immigration is ultimately about opportunity, hope, and building a brighter future. At Marinoff &amp; Associates, P.C., we are honored to help individuals and families pursue their goals and navigate the complexities of the immigration system with confidence and peace of mind.</p><p>Whether you are applying for a visa, seeking permanent residency, pursuing U.S. citizenship, or facing an immigration challenge, our team is here to stand beside you every step of the way.</p><p><strong>Protecting Families. Creating Opportunities. Building Futures.</strong></p><p><strong>Contact Marinoff &amp; Associates, P.C. today to schedule a consultation and learn how we can help you achieve your immigration goals.</strong></p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"93939318-2356-414d-96c7-03c6054f3813","name":"","text":"","type":"image","column":"right","settings":{"alt":"Green card and citizenship legal services","url":"https://lirp.cdn-website.com/03f0d32c/dms3rep/multi/opt/statue-of-liberty-statue-liberty-usa-47086-1920w.jpeg","size":"90","effect":"none","newTab":"false","linkUrl":"","variant":"image","alignment":"center","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffff