ze":"75","effect":"none","newTab":"false","linkUrl":"","variant":"logo","alignment":"left","borderColor":"#c5a059","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"2","horizontalOffset":"0"}}],"alignment":"left","canonical":true,"isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"center","center":"left"},"cellShadow":{"left":"none","right":"none","center":"none"},"cellVAlign":{"left":"top","right":"top","center":"center"},"cellOpacity":{"left":"1","right":"1","center":"1"},"cellPadding":{"left":"0","right":"0","center":"0"},"marginBottom":"20","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false","center":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","savedSectionId":"saved_section_1781826409772_rcsh6r","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"center":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#d9e4ef","right":"#999999","center":"#ffffff"},"cellBorderStyle":{"left":"solid","right":"solid","center":"solid"},"cellBorderWidth":{"left":"0","right":"0","center":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"0","right":"14","center":"20"},"cellMobileHidden":{"left":"false","right":"false","center":"false"},"cellDesktopHidden":{"left":"false","right":"false","center":"false"},"cellVerticalMargin":{"left":"0","right":"0","center":"0"}},{"id":"348037cd-5139-48ea-86f2-3a03d32d4242","title":"Content Block 1","layout":"two-column","locked":false,"modules":[{"id":"module-ae640e95-5fca-45de-aaea-7ba97866a0d2","name":"","text":"<h1>Abogados de Defensa Penal e Inmigración en Colorado</h1><h2>Marinoff &amp; Associates, P.C.</h2><p>Protegiendo Sus Derechos. Su Familia. Su Futuro.</p><p>En <strong>Marinoff &amp; Associates, P.C.</strong>, entendemos que enfrentar un problema legal puede ser uno de los momentos más difíciles de su vida. Ya sea que esté enfrentando cargos criminales, luchando por mantener a su familia unida o buscando alcanzar el sueño americano mediante un proceso de inmigración, nuestro equipo está aquí para brindarle la experiencia, la dedicación y el apoyo que usted merece.</p><p>Dirigido por el abogado <strong>Brandon Marinoff</strong>, nuestro despacho representa a clientes en todo Colorado con un enfoque basado en la honestidad, la comunicación clara y una defensa agresiva de sus derechos. Cada caso es único y cada cliente recibe atención personalizada desde la primera consulta hasta la resolución final de su asunto legal.</p><p><strong>Se Habla Español.</strong></p><h2>Conozca al Abogado Brandon Marinoff</h2><p>Brandon Marinoff es fundador de <strong>Marinoff &amp; Associates, P.C.</strong> y cuenta con más de tres décadas de experiencia legal.</p><p>Antes de ejercer en la práctica privada, fue <strong>Fiscal del Condado de Weld</strong> y posteriormente dirigió la <strong>Unidad Contra el Narcotráfico del Condado de Weld</strong>, adquiriendo amplia experiencia en investigaciones criminales, juicios y negociaciones complejas.</p><p>Esa experiencia como fiscal le permite anticipar las estrategias de la acusación y desarrollar defensas sólidas para proteger los derechos de sus clientes.</p><p>El Sr. Marinoff obtuvo su licenciatura en <strong>St. John''s University</strong> en 1984 y su título de Juris Doctor en <strong>Touro Law School</strong> en 1991. Originalmente es de Long Island, Nueva York, y desde hace muchos años sirve orgullosamente a personas y familias en todo Colorado.</p><h2>Áreas de Práctica</h2><h2>Defensa Penal</h2><p>Un arresto o una investigación criminal puede poner en riesgo su libertad, su empleo, su licencia de conducir, su reputación e incluso su estatus migratorio.</p><p>Representamos clientes acusados de:</p><ul><li><p>DUI/DWAI</p></li><li><p>Delitos relacionados con drogas</p></li><li><p>Violencia doméstica</p></li><li><p>Delitos graves (Felonies)</p></li><li><p>Delitos menores (Misdemeanors)</p></li><li><p>Robo</p></li><li><p>Agresión</p></li><li><p>Violaciones de libertad condicional</p></li><li><p>Órdenes de protección</p></li><li><p>Delitos juveniles</p></li><li><p>Delitos de tránsito</p></li></ul><p>Trabajamos para proteger sus derechos constitucionales y obtener el mejor resultado posible.</p><h2>Derecho de Inmigración</h2><p>Estados Unidos ofrece grandes oportunidades, pero el sistema migratorio puede ser complejo y cambiar constantemente.</p><p>Nuestro despacho ayuda a personas y familias con:</p><ul><li><p>Residencia Permanente (Green Card)</p></li><li><p>Ciudadanía Americana</p></li><li><p>Naturalización</p></li><li><p>Peticiones Familiares</p></li><li><p>Visas de Trabajo</p></li><li><p>Visas de Estudiante</p></li><li><p>Visas de Negocios e Inversionistas</p></li><li><p>Visas U para víctimas de delitos</p></li><li><p>VAWA</p></li><li><p>Asilo</p></li><li><p>Ajuste de Estatus</p></li><li><p>Perdones (Waivers)</p></li><li><p>Defensa contra Deportación</p></li><li><p>Renovación de Residencia</p></li><li><p>Permisos de Trabajo</p></li><li><p>Procesamiento Consular</p></li></ul><p>Nuestro objetivo es ayudarle a construir un futuro seguro para usted y su familia.</p><h2>Casos de Inmigración y Defensa Penal</h2><p>Uno de los aspectos que distingue a Marinoff &amp; Associates es nuestra experiencia en casos donde el derecho penal y la inmigración se cruzan.</p><p>Una condena penal puede afectar gravemente su situación migratoria, incluyendo:</p><ul><li><p>Deportación</p></li><li><p>Negación de residencia</p></li><li><p>Negación de ciudadanía</p></li><li><p>Inadmisibilidad</p></li><li><p>Pérdida de beneficios migratorios</p></li></ul><p>Gracias a nuestra experiencia como ex fiscal y abogado de inmigración, desarrollamos estrategias para minimizar estos riesgos y proteger tanto su libertad como su futuro en Estados Unidos.</p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"86aa7632-5560-46ab-b6f7-d401d6ff04a3","name":"Justice","text":"","type":"image","column":"right","settings":{"alt":"Abogados de Defensa Penal e Inmigración en Colorado","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1782757060150_Marinoff_Law_-_Quote_-_SPanish.png","altText":"Image","linkUrl":"","imageUrl":"","maxWidth":"100","alignment":"center","maxWidthPx":"0","aspectRatio":"auto","borderRadius":"20","imageAssetId":"289","overlayOpacity":"0","verticalOffset":"0","borderThickness":"1","horizontalOffset":"0"}},{"id":"image-1782758438440","name":"Justice (copy)","text":"","type":"image","column":"right","settings":{"alt":"Abogados de Defensa Penal e Inmigración en Colorado","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1782757060150_Marinoff_Law_-_Quote_-_SPanish.png","altText":"Image","linkUrl":"","imageUrl":"","maxWidth":"100","alignment":"center","maxWidthPx":"0","aspectRatio":"auto","borderRadius":"20","imageAssetId":"289","overlayOpacity":"0","verticalOffset":"0","borderThickness":"1","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#999999","right":"#999999"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"14","right":"14"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"section-1f91ac86-7404-42e9-a918-2e3386311456","title":"Content Block 2","layout":"two-column","locked":false,"modules":[{"id":"module-665ef090-ec37-4f92-b4b4-307af246259f","name":"","text":"","type":"image","column":"left","settings":{"alt":"","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/Stock_Photos/1781989828720_Marinoff_Law_-_Quotes_-_Spanish.png","size":"100","effect":"none","newTab":"false","linkUrl":"","variant":"image","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}},{"id":"module-aeeafe39-cf70-4bfb-a824-7a8e28eb9f48","name":"","text":"<h1>¿Por Qué Elegir a Brandon Marinoff?</h1><p>En <strong>Marinoff &amp; Associates, P.C.</strong>, creemos que un buen abogado hace mucho más que conocer la ley. También debe escuchar, comprender y acompañar a sus clientes durante uno de los momentos más importantes y difíciles de sus vidas. Sabemos que detrás de cada caso existe una persona, una familia y un futuro que merece ser protegido.</p><p>El abogado <strong>Brandon Marinoff</strong> ha dedicado más de tres décadas a representar a personas de todos los ámbitos de la vida. Ya sea que enfrente un proceso penal o un asunto de inmigración, usted recibirá la misma atención, respeto y compromiso que merece. Nuestro objetivo no es simplemente resolver un caso, sino ayudarle a recuperar la tranquilidad y brindarle la confianza necesaria para seguir adelante.</p><h2>Atención Personalizada</h2><p>En nuestro despacho usted nunca será un número de expediente. Brandon Marinoff dedica el tiempo necesario para conocer su historia, entender sus preocupaciones y desarrollar una estrategia legal adaptada a sus necesidades específicas. Cada caso recibe atención individualizada y una comunicación constante durante todo el proceso.</p><h2>Honestidad y Transparencia</h2><p>Creemos que la confianza comienza con la honestidad. Desde la primera consulta, Brandon Marinoff le explicará claramente su situación legal, las opciones disponibles y las posibles consecuencias de cada decisión. Nunca hacemos promesas imposibles; ofrecemos evaluaciones realistas, orientación sincera y expectativas claras.</p><h2>Compasión y Respeto</h2><p>Muchas personas llegan a nuestro despacho sintiendo miedo, incertidumbre o preocupación por su futuro. Nuestro equipo entiende el impacto emocional que un problema legal puede tener sobre usted y su familia. Por eso tratamos a cada cliente con dignidad, empatía y absoluto respeto, brindando apoyo durante todo el proceso legal.</p><h2>Amplia Experiencia</h2><p>Como <strong>ex Fiscal del Condado de Weld</strong> y ex director de la <strong>Unidad Contra el Narcotráfico del Condado de Weld</strong>, Brandon Marinoff conoce el sistema judicial desde ambos lados. Esa experiencia le permite anticipar las estrategias de la fiscalía y construir defensas sólidas y bien fundamentadas para proteger los intereses de sus clientes.</p><h2>Experiencia en Casos de Inmigración y Defensa Penal</h2><p>Pocos abogados poseen experiencia significativa tanto en derecho penal como en derecho de inmigración. Cuando un caso criminal puede afectar su estatus migratorio, contar con un abogado que comprenda ambas áreas del derecho puede marcar una diferencia importante en el resultado de su caso.</p><h2>Comunicación Clara</h2><p>Los asuntos legales pueden ser complicados y generar muchas dudas. Nos aseguramos de mantenerlo informado en cada etapa del proceso, responder sus preguntas con rapidez y explicarle cada paso en un lenguaje claro y fácil de entender.</p><h2>Estrategias Personalizadas</h2><p>No existen dos casos iguales. Analizamos cuidadosamente todos los detalles, investigamos las circunstancias particulares de cada cliente y diseñamos una estrategia legal enfocada en alcanzar el mejor resultado posible.</p><h2>Defensa Firme de Sus Derechos</h2><p>Cuando aceptamos un caso, lo hacemos con el compromiso de defender vigorosamente los derechos de nuestros clientes. Ya sea mediante negociación o litigio, trabajamos con determinación para obtener el mejor resultado posible.</p><h2>Se Habla Español</h2><p>Estamos orgullosos de servir a la comunidad hispana de Colorado. Nuestro equipo ofrece atención en español para que usted pueda comprender plenamente sus derechos, hacer preguntas con confianza y participar activamente en cada decisión relacionada con su caso.</p><h2>Nuestro Compromiso</h2><p>En Marinoff &amp; Associates, P.C., sabemos que nuestros clientes depositan en nosotros algo invaluable: su confianza. Por ello trabajamos cada día con profesionalismo, integridad y dedicación para proteger lo que más importa: <strong>su libertad, su familia, su futuro y su tranquilidad.</strong></p><h3>Porque para nosotros...</h3><ul><li><p><strong>Cada caso es personal.</strong></p></li><li><p><strong>Cada cliente importa.</strong></p></li><li><p><strong>Cada historia merece ser escuchada.</strong></p></li><li><p><strong>Cada persona merece una defensa sólida y una representación honesta.</strong></p></li></ul><h2>Marinoff &amp; Associates, P.C.</h2><h3>Sus Derechos. Su Familia. Su Futuro. Nuestro Compromiso.</h3><p></p>","type":"text","column":"right","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"transparent","right":"transparent"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"24","right":"24"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"2b3fa822-2b2f-4f37-bd02-894c5df591a2","title":"Content Block 2","layout":"two-column","locked":false,"modules":[{"id":"6d7dac8f-2997-4df1-bbb9-b75822eb46cd","name":"","text":"<h1>Nuestras Oficinas</h1><h2>Westminster</h2><p><strong>12207 N Pecos St. #700</strong><br>Westminster, CO 80234</p><h2>Brighton</h2><p><strong>14791 Brighton Rd</strong><br>Brighton, CO 80601</p><h2>Greeley</h2><p><strong>818 11th Ave</strong><br>Greeley, CO 80631</p><h1>Programe una Consulta</h1><p>Si necesita ayuda con un asunto de <strong>defensa penal o inmigración</strong>, no espere para obtener asesoría legal.</p><p>Nuestro equipo está listo para escuchar su situación, responder sus preguntas y ayudarle a desarrollar la mejor estrategia para proteger sus derechos.</p><p>Puede llamarnos o completar el formulario de contacto en nuestro sitio web para programar una consulta confidencial.</p><h2>Teléfonos</h2><p><strong>720-373-3508</strong></p><p><strong>720-216-4766</strong></p><h2>Sitio Web</h2><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"http://www.brandonmarinoff.com\"><strong>www.brandonmarinoff.com</strong></a></p><h1>Marinoff &amp; Associates, P.C.</h1><h2>Sus Derechos.</h2><h2>Su Familia.</h2><h2>Su Futuro.</h2><h2>Nuestro Compromiso.</h2><p></p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"4c5c1657-ff9a-4004-bb9d-d63779f320b9","name":"","text":"","type":"image","column":"right","settings":{"alt":"","url":"https://lirp.cdn-website.com/03f0d32c/dms3rep/multi/opt/AdobeStock_1314941326-1920w.jpeg","size":"100","effect":"none","newTab":"false","linkUrl":"","variant":"image","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none