"},"cellVerticalMargin":{"left":"0","right":"0","center":"0"}},{"id":"348037cd-5139-48ea-86f2-3a03d32d4242","title":"Content Block 1","layout":"two-column","locked":false,"modules":[{"id":"module-ae640e95-5fca-45de-aaea-7ba97866a0d2","name":"","text":"<h1>Our Team</h1><h2>Dedicated Advocates. Compassionate Counsel. Trusted Representation.</h2><p>At <strong>Marinoff &amp; Associates, P.C</strong>., we believe that exceptional legal representation begins with exceptional people. Our team is committed to providing knowledgeable, personalized, and compassionate legal services to individuals and families throughout Colorado. We understand that legal matters are often stressful, emotional, and life-changing, which is why we work closely with every client to provide clear guidance, honest communication, and strong advocacy every step of the way.</p><p>Whether you are facing criminal charges or dealing with complex immigration issues, our team is here to listen, answer your questions, and help you move forward with confidence. We take pride in building meaningful relationships with our clients and treating every case with the attention, care, and dedication it deserves.</p><p></p><h1>A Team Approach to Your Success</h1><p>At <strong>Marinoff &amp; Associates, P.C</strong>., you are never just another case number. We work collaboratively to ensure that every detail of your matter is carefully reviewed, and every legal strategy is thoughtfully developed. By combining experience, preparation, and a client-focused approach, we strive to deliver practical solutions and the strongest possible representation.</p><p><strong>Our team is dedicated to:</strong></p><ul><li><p>Providing personalized attention and responsive communication</p></li><li><p>Protecting your rights and advocating for your best interests</p></li><li><p>Offering compassionate support during difficult times</p></li><li><p>Developing strategic legal solutions tailored to your unique circumstances</p></li><li><p>Guiding you through the legal process with clarity and confidence</p></li></ul><p></p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"86aa7632-5560-46ab-b6f7-d401d6ff04a3","name":"Justice","text":"","type":"image","column":"right","settings":{"alt":"Justice","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1782513892737_Marinoff_and_Associates_-_Our_Team_of_Attorneys.png","altText":"Image","linkUrl":"","imageUrl":"","maxWidth":"100","alignment":"center","maxWidthPx":"0","aspectRatio":"auto","borderRadius":"20","imageAssetId":"289","overlayOpacity":"0","verticalOffset":"0","borderThickness":"1","horizontalOffset":"0"}},{"id":"module-1bf1973f-fb8e-4910-8211-fa79379ef999","name":"","text":"","type":"image","column":"right","settings":{"alt":"","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1782675914413_Learn_ABout_Brandon_Marinoff.png","size":"100","effect":"none","newTab":"false","linkUrl":"/brandon-marinoff-bio","variant":"image","borderColor":"#0f4f8f","borderRadius":"20","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"1","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#999999","right":"#999999"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"14","right":"14"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"d7302fe9-ff68-431e-a686-d900e683c284","title":"Content Block 2 Team","layout":"single","locked":false,"modules":[{"id":"6d7f2150-2595-4a9f-8f0c-afb8f4400473","name":"","text":"","type":"image","column":"main","settings":{"alt":"","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1782673105106_teammarinoff.jpg","size":"75","effect":"none","newTab":"false","linkUrl":"","variant":"image","alignment":"center","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"main":"left"},"cellShadow":{"main":"none"},"cellVAlign":{"main":"top"},"cellOpacity":{"main":"1"},"cellPadding":{"main":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"main":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"main":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"main":"transparent"},"cellBorderStyle":{"main":"solid"},"cellBorderWidth":{"main":"0"},"rowBorderRadius":"0","cellBorderRadius":{"main":"24"},"cellMobileHidden":{"main":"false"},"cellDesktopHidden":{"main":"false"},"cellVerticalMargin":{"main":"0"}},{"id":"section-1f91ac86-7404-42e9-a918-2e3386311456","title":"Content Block 2","layout":"two-column","locked":false,"modules":[{"id":"module-665ef090-ec37-4f92-b4b4-307af246259f","name":"","text":"","type":"image","column":"left","settings":{"alt":"Criminal Defense and Immigration Attorneys","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1782834135751_Criminal_Lawyer_and_Immigration_Attorneys.png","size":"100","effect":"none","newTab":"false","linkUrl":"","variant":"image","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}},{"id":"module-aeeafe39-cf70-4bfb-a824-7a8e28eb9f48","name":"","text":"<h1>Every Client Matters. Every Case Is Personal</h1><p>At <strong>Marinoff &amp; Associates, P.C</strong>., we understand that behind every legal matter is a real person facing uncertainty, stress, and important life decisions. Whether you are worried about your freedom, your family, your immigration status, or your future, our team is committed to providing more than legal representation—we provide guidance, support, and a trusted partnership when you need it most. We take pride in treating every client with respect, compassion, and personal attention because we know that every case has the potential to change someone''s life.</p><h1>Committed to Excellence and Community</h1><p>Our team is built on the principles of integrity, preparation, and service. We believe effective representation begins with listening carefully, communicating clearly, and advocating passionately for our clients'' goals. From the first consultation to the resolution of your case, we work diligently to provide knowledgeable counsel and practical solutions tailored to your unique circumstances. We are honored by the trust our clients place in us and remain dedicated to serving individuals and families throughout Colorado with professionalism, compassion, and unwavering commitment.</p><h1>A Team You Can Trust</h1><p>Legal challenges can feel overwhelming, but you should never have to face them alone. At Marinoff &amp; Associates, P.C., we believe that trust, communication, and genuine care are just as important as legal knowledge and courtroom experience.</p><p>Our team is committed to being accessible, responsive, and supportive throughout every stage of your case. We understand that important decisions often come during some of life''s most difficult moments, and we strive to provide the guidance, reassurance, and advocacy you need to move forward with confidence.</p><h1>More Than Legal Representation</h1><p>Every client who walks through our doors deserves to feel heard, respected, and valued. Whether we are defending your rights in a criminal case, helping your family navigate a major transition, or guiding you through the complexities of immigration law, our mission remains the same: to provide exceptional legal representation while treating every client with compassion, dignity, and unwavering commitment. Because to us, your case is never just a file—it is your life, your future, and a responsibility we are honored to protect.</p><p><strong>At Marinoff &amp; Associates, P.C., you''re not just hiring a law firm—you''re gaining a team that genuinely cares about your rights, your family, and your future.</strong></p><p></p>","type":"text","column":"right","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"transparent","right":"transparent"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"24","right":"24"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"f07f6300-8c64-4b18-af48-35e368daaa53","title":"Content Block 3","layout":"two-column","locked":false,"modules":[{"id":"da69ff6b-9ce7-4b2f-8764-08c5e59ab28c","name":"","text":"<h1>Serving Colorado Communities</h1><p>With offices conveniently located in <strong>Westminster, Brighton, and Greeley</strong>, Marinoff &amp; Associates proudly serves clients throughout Colorado. We understand that behind every legal matter is a person, a family, and a future that deserves protection.</p><p><strong>Legal problems are personal. Your representation should be too.</strong></p><p>At Marinoff &amp; Associates, P.C., we are honored to stand beside our clients when they need trusted legal guidance the most.</p><p><strong>Your Rights. Your Family. Your Future. Our Commitment.</strong></p><p></p><h1>Contact Our Team Today</h1><p>When you are facing a legal challenge, the decisions you make today can have a lasting impact on your future. Whether you need guidance in a criminal defense matter or immigration case, the experienced team at Marinoff &amp; Associates, P.C. is here to help. We take the time to understand your situation, answer your questions, and develop a legal strategy tailored to your unique needs and goals.</p><p>You do not have to navigate the legal system alone. Let our team provide the trusted advice, compassionate support, and strong advocacy you deserve.</p><p><strong>Schedule a confidential consultation today and discover how Marinoff &amp; Associates can help protect your rights, your family, and your future.</strong></p><p>📞 <strong>Call:</strong> 720-373-3508 <em>(Se Habla Español)</em> or 720-216-4766<br>📍 <strong>Offices:</strong> Westminster • Brighton • Greeley<br>🌐 <strong>Website:</strong> <a target=\"_blank\" rel=\"noopener noreferrer\" href=\"http://www.brandonmarinoff.com\">www.brandonmarinoff.com</a></p><p><strong>Marinoff &amp; Associates, P.C.</strong><br><em>Dedicated Advocates. Trusted Counsel. Results That Matter.</em><br><strong>Your Rights. Your Family. Your Future. Our Commitment.</strong></p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"3dfee992-8708-4463-9ee1-9c0a48e706d7","name":"","text":"","type":"image","column":"right","settings":{"alt":"","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/Stock_Photos/1781989843006_Brandon_Marinoff_Testimonial.png","size":"75","effect":"none","newTab":"false","linkUrl":"","variant":"image","alignment":"center","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderT