ng","size":"75","effect":"none","newTab":"false","linkUrl":"","variant":"logo","alignment":"left","borderColor":"#c5a059","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"2","horizontalOffset":"0"}}],"alignment":"left","canonical":true,"isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"center","center":"left"},"cellShadow":{"left":"none","right":"none","center":"none"},"cellVAlign":{"left":"top","right":"top","center":"center"},"cellOpacity":{"left":"1","right":"1","center":"1"},"cellPadding":{"left":"0","right":"0","center":"0"},"marginBottom":"20","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false","center":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","savedSectionId":"saved_section_1781826409772_rcsh6r","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"center":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#d9e4ef","right":"#999999","center":"#ffffff"},"cellBorderStyle":{"left":"solid","right":"solid","center":"solid"},"cellBorderWidth":{"left":"0","right":"0","center":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"0","right":"14","center":"20"},"cellMobileHidden":{"left":"false","right":"false","center":"false"},"cellDesktopHidden":{"left":"false","right":"false","center":"false"},"cellVerticalMargin":{"left":"0","right":"0","center":"0"}},{"id":"348037cd-5139-48ea-86f2-3a03d32d4242","title":"Content Block 1","layout":"two-column","locked":false,"modules":[{"id":"module-ae640e95-5fca-45de-aaea-7ba97866a0d2","name":"","text":"<h1>Greeley Criminal Defense and Immigration Lawyer</h1><h2>Experienced Legal Representation in Greeley, Colorado</h2><p>When your freedom, immigration status, family, or future is at risk, you need an attorney who understands the law and the local legal system.</p><p>Attorney <strong>Brandon Marinoff</strong> and the team at <strong>Marinoff &amp; Associates, P.C.</strong> represent clients in Greeley and throughout Weld County in matters involving <strong>criminal defense and immigration law</strong>.</p><p>Brandon is a former Weld County prosecutor and former head of the Weld County Drug Task Force. His experience provides valuable insight into how criminal cases are investigated, charged, negotiated, and prosecuted in Weld County.</p><p>Whether you have been arrested, are facing removal proceedings, need help obtaining lawful immigration status, or are dealing with a difficult family matter, our firm will listen to your concerns, explain your options, and develop a legal strategy based on your circumstances.</p><p><strong>Se Habla Español.</strong></p><h3>Greeley Office</h3><p><strong>Marinoff &amp; Associates, P.C.</strong><br>818 11th Ave, Greeley, CO 80631</p><p><strong>Phone:</strong> 720-216-4766<br><strong>Main Office:</strong> 720-373-3508</p><p>Call our office or complete the website contact form to request a consultation.</p><h2>Greeley Criminal Defense Lawyer</h2><p>Being arrested or accused of a crime can affect nearly every part of your life. Depending on the charge, you may face jail, fines, probation, loss of employment, restrictions on your rights, or lasting damage to your reputation.</p><p>You should not assume that an arrest will automatically result in a conviction. The prosecution must prove its case, and there may be important questions involving the evidence, witnesses, police procedures, searches, statements, or constitutional rights.</p><p>As a <strong>Greeley criminal defense lawyer</strong> and former prosecutor, Brandon Marinoff understands how the government approaches criminal cases. He carefully analyzes the facts, identifies weaknesses in the prosecution’s case, and helps clients understand their available defenses.</p><h2>Criminal Cases We Handle</h2><p>Marinoff &amp; Associates represents clients facing charges involving:</p><ul><li><p>DUI and DWAI</p></li><li><p>Drug possession and distribution</p></li><li><p>Domestic violence</p></li><li><p>Assault and violent offenses</p></li><li><p>Theft and property crimes</p></li><li><p>Felony and misdemeanor charges</p></li><li><p>Traffic offenses</p></li><li><p>Probation violations</p></li><li><p>Juvenile offenses</p></li><li><p>Weapons charges</p></li><li><p>Sex offense allegations</p></li><li><p>Criminal mischief</p></li><li><p>Restraining and protection orders</p></li></ul><h2>Greeley DUI Lawyer</h2><p>A DUI or DWAI arrest can create two separate problems: a criminal court case and a driver’s license matter. Deadlines may apply, so it is important to obtain legal guidance as soon as possible.</p><p>A <strong>Greeley DUI lawyer</strong> can review the traffic stop, field sobriety testing, chemical test results, officer reports, and other evidence. Our firm helps clients understand both the criminal and driver’s license consequences of a Colorado DUI charge.</p><h2>Greeley Drug Crime Attorney</h2><p>Brandon’s experience as the former head of the Weld County Drug Task Force gives him substantial knowledge of drug investigations and prosecutions.</p><p>Drug cases may involve complicated issues concerning:</p><ul><li><p>Search and seizure</p></li><li><p>Search warrants</p></li><li><p>Confidential informants</p></li><li><p>Surveillance</p></li><li><p>Vehicle searches</p></li><li><p>Possession versus intent to distribute</p></li><li><p>Laboratory testing</p></li><li><p>Statements made to police</p></li><li><p>Constructive possession</p></li><li><p>Drug task force investigations</p></li></ul><p>If you need a <strong>Greeley drug crime lawyer</strong>, our firm can examine how the investigation was conducted and determine whether the government’s evidence can be challenged.</p><h2>Domestic Violence Defense in Greeley</h2><p>A domestic violence arrest can quickly affect your freedom, home, family, employment, and ability to possess firearms. A protection order may also prevent you from returning home or communicating with certain family members.</p><p>Brandon Marinoff represents clients accused of domestic violence-related offenses and works to protect their rights while helping them comply with court orders.</p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"86aa7632-5560-46ab-b6f7-d401d6ff04a3","name":"Justice","text":"","type":"image","column":"right","settings":{"alt":"Greeley Colorado Lawyer","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1782751445719_Brandon_Marinoff_-_Greeley_Colorado_Lawyer.png","altText":"Image","linkUrl":"","imageUrl":"","maxWidth":"100","alignment":"center","maxWidthPx":"0","aspectRatio":"auto","borderRadius":"20","imageAssetId":"289","overlayOpacity":"0","verticalOffset":"0","borderThickness":"1","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#999999","right":"#999999"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"14","right":"14"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"section-1f91ac86-7404-42e9-a918-2e3386311456","title":"Content Block 2","layout":"two-column","locked":false,"modules":[{"id":"module-aeeafe39-cf70-4bfb-a824-7a8e28eb9f48","name":"","text":"<h2>Greeley Immigration Lawyer</h2><p>Immigration law can affect where you live, whether you can work, whether your family can remain together, and whether you can build a permanent future in the United States.</p><p>As an experienced <strong>Greeley immigration lawyer</strong>, Brandon assists individuals and families with immigration applications, removal matters, waivers, and cases involving both immigration and criminal law.</p><h2>Immigration Services</h2><p>Our Greeley immigration practice includes:</p><ul><li><p>Green cards and permanent residence</p></li><li><p>Family-based immigration</p></li><li><p>Marriage-based immigration</p></li><li><p>U.S. citizenship and naturalization</p></li><li><p>Deportation and removal defense</p></li><li><p>Immigration bond hearings</p></li><li><p>Asylum matters</p></li><li><p>Immigration waivers</p></li><li><p>U visas</p></li><li><p>VAWA petitions</p></li><li><p>DACA matters</p></li><li><p>Student visas</p></li><li><p>Business and investment visas</p></li><li><p>Employment authorization</p></li><li><p>Adjustment of status</p></li><li><p>Consular processing</p></li></ul><h2>Deportation and Removal Defense</h2><p>Removal proceedings can place your family, career, and future in the United States at risk. If you receive a Notice to Appear, are detained by immigration authorities, or believe you may face deportation, speak with an immigration attorney promptly.</p><p>A <strong>Greeley deportation lawyer</strong> can evaluate your immigration history, family relationships, criminal record, and possible forms of relief. Depending on the circumstances, options may include asylum, cancellation of removal, adjustment of status, waivers, or other defenses.</p><h2>Green Cards and Citizenship</h2><p>Our firm helps eligible clients pursue lawful permanent residence through marriage, family relationships, employment, humanitarian programs, and other available pathways.</p><p>We also assist permanent residents who want to become United States citizens. A <strong>Greeley citizenship attorney</strong> can review your eligibility, identify potential complications, prepare your application, and help you get ready for the naturalization process.</p><h2>Criminal Charges and Immigration Consequences</h2><p>Criminal and immigration law frequently overlap. Even a misdemeanor charge or negotiated plea may create serious consequences for someone who is not a United States citizen.</p><p>A criminal case may affect:</p><ul><li><p>Lawful permanent residence</p></li><li><p>Visa eligibility</p></li><li><p>Naturalization</p></li><li><p>Admissibility</p></li><li><p>Immigration detention</p></li><li><p>Removal or deportation</p></li><li><p>Eligibility for future immigration benefits</p></li></ul><p>Brandon’s experience in both areas allows him to consider the criminal and immigration consequences of a case together. This is especially important for green card holders, visa holders, DACA recipients, and undocumented individuals facing criminal allegations.</p>","type":"text","column":"right","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"module-665ef090-ec37-4f92-b4b4-307af246259f","name":"","text":"","type":"image","column":"left","settings":{"alt":"Criminal Defense and Immigration Attorney","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1782751290733_Greeley_Attorney_-_Brandon_Marinoff.png","size":"100","effect":"none","newTab":"false","linkUrl":"","variant":"image","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"transparent","right":"transparent"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"24","right":"24"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"9a5140a8-b38e-420c-b425-3034787da823","title":"Content Block 2","layout":"two-column","locked":false,"modules":[{"id":"3dc5ce4e-23cb-49e0-9fe1-c15f64e68de8","name":"","text":"<h2>Serving Greeley and Weld County</h2><p>Greeley is the governmental center of Weld County and home to the University of Northern Colorado. It is a growing Northern Colorado community with deep agricultural roots and an increasingly diverse population. <a target=\"_new\" rel=\"noopener noreferrer\" class=\"decorated-link\" href=\"https://greeleyco.gov/economic-development/why-greeley/workforce-and-education/\">City of Greeley</a>, <a target=\"_new\" rel=\"noopener noreferrer\" class=\"decorated-link\" href=\"https://www.unco.edu/about/\">University of Northern Colorado</a></p><p>Our Greeley office serves clients from communities throughout the region, including:</p><ul><li><p>Greeley</p></li><li><p>Evans</p></li><li><p>Garden City</p></li><li><p>Windsor</p></li><li><p>Eaton</p></li><li><p>Severance</p></li><li><p>Johnstown</p></li><li><p>Milliken</p></li><li><p>Platteville</p></li><li><p>Fort Lupton</p></li><li><p>Other Weld County communities</p></li></ul><p>Brandon’s background as a former Weld County prosecutor gives him meaningful experience with the local legal system and the agencies involved in Weld County criminal cases.</p><h2>Why Choose Brandon Marinoff?</h2><h3>Former Weld County Prosecutor</h3><p>Brandon understands how prosecutors evaluate evidence, prepare witnesses, negotiate cases, and develop trial strategies.</p><h3>Former Drug Task Force Leader</h3><p>His experience leading the Weld County Drug Task Force provides particular insight into drug investigations, searches, informants, and law-enforcement procedures.</p><h3>Criminal and Immigration Experience</h3><p>Brandon is equipped to handle cases in which a criminal charge could threaten a client’s immigration status.</p><h3>Honest Legal Guidance</h3><p>Clients receive a straightforward assessment of their situation, including the potential advantages and disadvantages of their available options.</p><h3>Personal Attention</h3><p>Every legal matter has a person and family behind it. Brandon takes the time to understand what is at stake and what the client hopes to accomplish.</p><h2>Frequently Asked Questions</h2><h3>When should I contact a criminal defense lawyer?</h3><p>You should contact an attorney as soon as you learn that you are under investigation, have been arrested, or have received a summons. Early representation may help protect your rights and preserve important evidence.</p><h3>Can a criminal charge affect my immigration status?</h3><p>Yes. Certain convictions and plea agreements can affect visas, green cards, citizenship applications, admissibility, and removal proceedings. Speak with an attorney who understands both criminal and immigration law before accepting a plea.</p><h3>Do you represent clients outside Greeley?</h3><p>Yes. Marinoff &amp; Associates represents clients throughout Weld County and across Colorado, depending on the type of legal matter.</p><h3>Do you help Spanish-speaking clients?</h3><p>Yes. <strong>Se Habla Español.</strong> Our firm assists Spanish-speaking clients and families with criminal and immigration matters.</p><h2>What should I bring to my consultation?</h2><p>Bring any court documents, police reports, immigration notices, protection orders, bond paperwork, charging documents, or correspondence related to your case. Prepare a list of your questions and important dates as well.</p><h2>Speak With a Greeley Attorney</h2><p>Legal problems rarely resolve themselves. The earlier you understand your rights and options, the better prepared you will be to make informed decisions.</p><p>If you are searching for a <strong>Greeley criminal defense lawyer, Greeley immigration attorney, Greeley DUI lawyer, Weld County criminal defense attorney, or Greeley deportation lawyer</strong>, contact Marinoff &amp; Associates today.</p><p><strong>Marinoff &amp; Associates, P.C.</strong><br>818 11th Ave, Greeley, CO 80631</p><p><strong>Call 720-216-4766 or complete our online contact form to request a consultation.</strong></p><p><strong>Your Rights. Your Family. Your Future. Our Commitment.</strong></p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"95023423-957f-42ae-ab19-5b0b1475edea","name":"","text":"","type":"image","column":"right","settings":{"alt":"","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/Stock_Photos/1781876910857_Best_Attorney.png","size":"100","effect":"none","newTab":"false","linkUrl":"","variant":"image","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#f