ng","size":"75","effect":"none","newTab":"false","linkUrl":"","variant":"logo","alignment":"left","borderColor":"#c5a059","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"2","horizontalOffset":"0"}}],"alignment":"left","canonical":true,"isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"center","center":"left"},"cellShadow":{"left":"none","right":"none","center":"none"},"cellVAlign":{"left":"top","right":"top","center":"center"},"cellOpacity":{"left":"1","right":"1","center":"1"},"cellPadding":{"left":"0","right":"0","center":"0"},"marginBottom":"20","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false","center":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","savedSectionId":"saved_section_1781826409772_rcsh6r","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"center":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#d9e4ef","right":"#999999","center":"#ffffff"},"cellBorderStyle":{"left":"solid","right":"solid","center":"solid"},"cellBorderWidth":{"left":"0","right":"0","center":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"0","right":"14","center":"20"},"cellMobileHidden":{"left":"false","right":"false","center":"false"},"cellDesktopHidden":{"left":"false","right":"false","center":"false"},"cellVerticalMargin":{"left":"0","right":"0","center":"0"}},{"id":"348037cd-5139-48ea-86f2-3a03d32d4242","title":"Content Block 1","layout":"two-column","locked":false,"modules":[{"id":"module-ae640e95-5fca-45de-aaea-7ba97866a0d2","name":"","text":"<h1>Criminal Defense &amp; Immigration Attorney in Brighton, CO</h1><p>When your future, freedom, or immigration status is at stake, experience matters. At <strong>Marinoff &amp; Associates, P.C.</strong>, we proudly represent individuals and families throughout <strong>Brighton, Colorado</strong>, and surrounding Adams County communities. Our firm provides aggressive criminal defense and experienced immigration representation tailored to each client''s unique situation.</p><p>Attorney <strong>Brandon Marinoff</strong> is a former <strong>Weld County Prosecutor</strong> and former <strong>Head of the Weld County Drug Task Force</strong>, giving him valuable insight into how prosecutors investigate and build cases. Whether you''re facing criminal charges or navigating a complex immigration matter, our team is committed to protecting your rights and helping you move forward with confidence.</p><p></p><h2>Serving Brighton and Adams County</h2><p>Brighton is one of Colorado''s fastest-growing communities, located just northeast of Denver with convenient access to I-76, Denver International Airport, and the greater Front Range. As the county seat of Adams County, Brighton continues to attract families, professionals, and businesses while maintaining its welcoming small-town atmosphere.</p><p>Our Brighton office proudly serves clients throughout:</p><ul><li><p>Brighton</p></li><li><p>Commerce City</p></li><li><p>Henderson</p></li><li><p>Fort Lupton</p></li><li><p>Lochbuie</p></li><li><p>Reunion</p></li><li><p>Thornton</p></li><li><p>Northglenn</p></li><li><p>Adams County</p></li><li><p>Weld County</p></li></ul><p>Throughout Colorado</p><p></p><h2>Criminal Defense Lawyer in Brighton, CO</h2><p>Being arrested or charged with a crime can be overwhelming. The decisions you make in the first hours and days after an arrest can significantly impact your future.</p><p>Our criminal defense attorneys represent clients charged with:</p><ul><li><p>DUI &amp; DWAI</p></li><li><p>Drug Crimes</p></li><li><p>Domestic Violence</p></li><li><p>Assault</p></li><li><p>Theft &amp; Burglary</p></li><li><p>Juvenile Crimes</p></li><li><p>Probation Violations</p></li><li><p>Traffic Offenses</p></li><li><p>Felonies &amp; Misdemeanors</p></li><li><p>Weapons Charges</p></li><li><p>White Collar Crimes</p></li><li><p>Record Sealing &amp; Expungement</p></li></ul><p>As a former prosecutor, Brandon Marinoff understands how the government builds criminal cases and uses that knowledge to develop strategic defenses for his clients.</p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"86aa7632-5560-46ab-b6f7-d401d6ff04a3","name":"Justice","text":"","type":"image","column":"right","settings":{"alt":"Justice","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1782753459654_Brighton_Attorney_-_Criminal_Defense.png","altText":"Image","linkUrl":"","imageUrl":"","maxWidth":"100","alignment":"center","maxWidthPx":"0","aspectRatio":"auto","borderRadius":"20","imageAssetId":"289","overlayOpacity":"0","verticalOffset":"0","borderThickness":"1","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#999999","right":"#999999"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"14","right":"14"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"section-1f91ac86-7404-42e9-a918-2e3386311456","title":"Content Block 2","layout":"two-column","locked":false,"modules":[{"id":"module-665ef090-ec37-4f92-b4b4-307af246259f","name":"","text":"","type":"image","column":"left","settings":{"alt":"","url":"https://lirp.cdn-website.com/03f0d32c/dms3rep/multi/opt/AdobeStock_1314941326-1920w.jpeg","size":"100","effect":"none","newTab":"false","linkUrl":"","variant":"image","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}},{"id":"module-aeeafe39-cf70-4bfb-a824-7a8e28eb9f48","name":"","text":"<h2>Immigration Attorney in Brighton</h2><p>Immigration law affects every aspect of your future—from your family and career to your ability to remain in the United States. Our firm represents clients before USCIS, Immigration Court, and other immigration agencies.</p><p>We assist with:</p><ul><li><p>Family-Based Immigration</p></li><li><p>Green Cards</p></li><li><p>Adjustment of Status</p></li><li><p>Naturalization &amp; U.S. Citizenship</p></li><li><p>Student Visas</p></li><li><p>Business &amp; Investment Visas</p></li><li><p>Employment Visas</p></li><li><p>U Visas</p></li><li><p>VAWA Petitions</p></li><li><p>Family Petitions</p></li><li><p>Deportation Defense</p></li><li><p>Waivers</p></li><li><p>Consular Processing</p></li><li><p>Immigration Appeals</p></li></ul><p>Our firm is especially experienced in cases where <strong>criminal charges and immigration consequences overlap</strong>, helping clients understand and minimize the impact on their immigration status.</p><p></p><h2>Why Choose Marinoff &amp; Associates?</h2><h3>Former Prosecutor Experience</h3><p>Brandon Marinoff spent years prosecuting criminal cases before dedicating his practice to defending individuals and families throughout Colorado.</p><h3>Personalized Representation</h3><p>You are never treated like just another file. Every case receives individual attention, honest advice, and a customized legal strategy.</p><h3>Criminal &amp; Immigration Experience</h3><p>Few firms understand how criminal charges can affect immigration status. Our experience in both areas allows us to protect your future from every angle.</p><h3>Honest Communication</h3><p>We explain your legal options clearly, keep you informed throughout your case, and provide realistic expectations from the very beginning.</p><h3>Proven Advocacy</h3><p>Whether negotiating a favorable resolution or aggressively defending your rights in court, our goal is always the best possible outcome.</p>","type":"text","column":"right","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"transparent","right":"transparent"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"24","right":"24"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"23e10718-d00c-4bd2-8ab6-ea775742e494","title":"Content Block 2","layout":"two-column","locked":false,"modules":[{"id":"ad46ed2b-2ced-4bb3-8ee0-931541c45d0b","name":"","text":"<h2>Convenient Brighton Office</h2><p><strong>Marinoff &amp; Associates, P.C.</strong></p><p><strong>Brighton Office</strong><br><strong>14791 Brighton Rd</strong><br><strong>Brighton, CO 80601</strong></p><p><strong>Phone:</strong> 720-373-3508</p><p><strong>Additional Office:</strong> 720-216-4766</p><p><strong>Se Habla Español</strong></p><p></p><h2>Schedule Your Confidential Consultation</h2><p>Whether you''ve been arrested or need help with an immigration matter, Marinoff &amp; Associates is ready to help.</p><p>We understand that every legal situation is personal. Our attorneys take the time to listen, explain your options, and build a strategy designed to protect your rights, your family, and your future.</p><p>Contact our Brighton office today to schedule a confidential consultation with an experienced Colorado attorney.</p><p></p><h2>Frequently Asked Questions</h2><p>Do I need a criminal defense lawyer after an arrest in Brighton?</p><p>Yes. Speaking with an attorney as soon as possible can help protect your rights, preserve important evidence, and improve the outcome of your case.</p><h3>Can a criminal charge affect my immigration status?</h3><p>Absolutely. Certain convictions can impact visas, green cards, naturalization, and removal proceedings. If you are not a U.S. citizen, it''s important to speak with an attorney experienced in both criminal defense and immigration law.</p><h3>What immigration services do you offer?</h3><p>We assist with green cards, family petitions, citizenship, student visas, business visas, U Visas, VAWA petitions, waivers, deportation defense, and many other immigration matters.</p><h3>Do you offer consultations?</h3><p>Yes. Contact our Brighton office to discuss your legal matter and learn about your available options.</p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"ba82d089-f139-47b3-8d05-d96f401e91e3","name":"","text":"","type":"image","column":"right","settings":{"alt":"","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/Stock_Photos/1781876826599_Best_Case_Scenario.png","size":"100","effect":"none","newTab":"false","linkUrl":"","variant":"image","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom"