></h3><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://www.brandonmarinoff.com/\"><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">12207 Pecos St. Suite 700</span></a></p><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://www.brandonmarinoff.com/\"><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">Westminster, CO. 80234</span></a></p>","type":"text","column":"right","settings":{"text":"Contact Us","align":"left","textColor":"#173c61","headlineId":"","headingLevel":"H3"}},{"id":"module_1781293635840_3p0km","name":"Logo","text":"","type":"image","column":"left","settings":{"alt":"Brandon Marinoff & Associates","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1781469490414_Marinoff_and_Associates_Logo-1920.webp","size":"75","altText":"Image","linkUrl":"","imageUrl":"","maxWidth":"40","alignment":"center","maxWidthPx":"0","aspectRatio":"auto","borderRadius":"0","imageAssetId":"412","overlayOpacity":"0","verticalMargin":"50","verticalOffset":"0","horizontalOffset":"0"}},{"id":"module-1fc0b2d0-36b5-4df8-8cf7-0d947ea38f2a","name":"","text":"<h2>Learn More</h2><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"/home\"><span style=\"font-size: 20px;\"><strong>‣ Home</strong></span></a></p><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"/about-us\"><span style=\"font-size: 20px;\"><strong>‣ About Us</strong></span></a></p><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"/criminal-law\"><span style=\"font-size: 20px;\"><strong>‣ Criminal Law</strong></span></a></p><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"/immigration-law\"><span style=\"font-size: 20px;\"><strong>‣ Immigration Law</strong></span></a></p><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"/contact\"><span style=\"font-size: 20px;\"><strong>‣ Contact</strong></span></a></p>","type":"text","column":"center","settings":{"variant":"paragraph","mobileHidden":"false","desktopHidden":"false",