ng","size":"75","effect":"none","newTab":"false","linkUrl":"","variant":"logo","alignment":"left","borderColor":"#c5a059","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"2","horizontalOffset":"0"}}],"alignment":"left","canonical":true,"isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"center","center":"left"},"cellShadow":{"left":"none","right":"none","center":"none"},"cellVAlign":{"left":"top","right":"top","center":"center"},"cellOpacity":{"left":"1","right":"1","center":"1"},"cellPadding":{"left":"0","right":"0","center":"0"},"marginBottom":"20","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false","center":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","savedSectionId":"saved_section_1781826409772_rcsh6r","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"center":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#d9e4ef","right":"#999999","center":"#ffffff"},"cellBorderStyle":{"left":"solid","right":"solid","center":"solid"},"cellBorderWidth":{"left":"0","right":"0","center":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"0","right":"14","center":"20"},"cellMobileHidden":{"left":"false","right":"false","center":"false"},"cellDesktopHidden":{"left":"false","right":"false","center":"false"},"cellVerticalMargin":{"left":"0","right":"0","center":"0"}},{"id":"348037cd-5139-48ea-86f2-3a03d32d4242","title":"Content Block 1","layout":"two-column","locked":false,"modules":[{"id":"module-ae640e95-5fca-45de-aaea-7ba97866a0d2","name":"","text":"<h1>Removal Defense</h1><h2>Protecting Your Status. Defending Your Future.</h2><p>Facing deportation or removal proceedings can be one of the most frightening and uncertain experiences a person or family can endure. Your ability to remain in the United States, stay with your loved ones, continue your career, and pursue your future may suddenly feel at risk. The immigration system is complex, and the consequences of a removal case can be life changing. When everything you have worked to build is on the line, having experienced legal representation can make a meaningful difference.</p><p>At Marinoff &amp; Associates, P.C., we understand that removal defense is about much more than legal paperwork and court hearings. Behind every case is a person, a family, and a future that deserves to be protected. We provide knowledgeable, compassionate, and strategic representation for individuals and families facing deportation proceedings throughout Colorado. Our team works diligently to understand your circumstances, explain your options, and advocate for every available form of relief under the law.</p><h2>What Is Removal Defense?</h2><p>Removal defense, often referred to as deportation defense, involves representing individuals who are facing proceedings before an immigration judge and may be at risk of being removed from the United States. Removal proceedings can arise for many reasons, including visa violations, unlawful presence, criminal charges or convictions, denied immigration applications, allegations of fraud or misrepresentation, or other immigration-related issues.</p><p>While receiving a Notice to Appear or learning that you are in removal proceedings can be overwhelming, it does not automatically mean that deportation is inevitable. Many individuals may have legal defenses or forms of relief that allow them to remain in the United States. Understanding your rights and seeking legal counsel as early as possible is critical.</p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"86aa7632-5560-46ab-b6f7-d401d6ff04a3","name":"Removal Defense","text":"","type":"image","column":"right","settings":{"alt":"Deportation removal defense attorney","url":"https://irp.cdn-website.com/03f0d32c/dms3rep/multi/pexels-photo-7044342.jpeg","size":"90","altText":"Image","linkUrl":"","imageUrl":"","maxWidth":"100","alignment":"center","maxWidthPx":"0","aspectRatio":"auto","borderRadius":"20","imageAssetId":"289","overlayOpacity":"0","verticalOffset":"0","borderThickness":"1","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#999999","right":"#999999"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"14","right":"14"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"section-1f91ac86-7404-42e9-a918-2e3386311456","title":"Content Block 2","layout":"two-column","locked":false,"modules":[{"id":"module-aeeafe39-cf70-4bfb-a824-7a8e28eb9f48","name":"","text":"<h2>Why Choose Marinoff &amp; Associates?</h2><ol><li><p><strong>Experienced Removal Defense Attorneys:</strong> Our team has extensive experience representing clients in removal proceedings and defending against deportation. We understand the complex laws and procedures involved in removal defense and have a proven track record of achieving successful outcomes.</p></li><li><p><strong>Personalized Defense Strategies:</strong> Every removal case is unique. We work closely with you to understand your situation and develop a tailored defense strategy that explores all possible avenues of relief, from cancellation of removal to asylum and adjustment of status.</p></li><li><p><strong>Comprehensive Legal Guidance:</strong> We provide comprehensive legal services throughout the removal process, helping you understand the charges against you, your rights, and your options for defense. We will guide you every step of the way, from court appearances to gathering supporting documentation.</p></li><li><p><strong>Aggressive Representation in Court:</strong> If your case goes to court, we will provide aggressive and strategic representation, working to present the strongest possible defense to prevent your removal and secure a favorable outcome.</p></li></ol><p><br></p>","type":"text","column":"right","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"module-665ef090-ec37-4f92-b4b4-307af246259f","name":"","text":"","type":"image","column":"left","settings":{"alt":"Removal defense lawyer","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1782499095411_Brandon_Marinoff_-_Marinoff_and_Associates_PC.png","size":"90","effect":"none","newTab":"false","linkUrl":"","variant":"image","alignment":"center","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"transparent","right":"transparent"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"24","right":"24"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"615d6dd2-cb3e-4f5b-ab40-a85baac5a691","title":"Content Block 3","layout":"two-column","locked":false,"modules":[{"id":"e275d7ee-b833-4ee8-8414-2881446ebe1c","name":"","text":"<h2>How We Can Help:</h2><ul><li><p><strong>Cancellation of Removal:</strong> If you meet the eligibility requirements, we can help you apply for cancellation of removal, which may allow you to stay in the U.S. and adjust your status to lawful permanent resident.</p></li><li><p><strong>Asylum and Refugee Status:</strong> If you fear returning to your home country due to persecution, we can help you apply for asylum or refugee status to prevent deportation and remain in the U.S.</p></li><li><p><strong>Adjustment of Status:</strong> If you are eligible for a green card through family or employment, we can assist you in adjusting your status while defending against removal, so you can stay in the country legally.</p></li><li><p><strong>Waivers of Inadmissibility:</strong> If you have certain inadmissibility issues, such as criminal convictions or immigration violations, we can help you apply for a waiver to overcome these barriers and remain in the U.S.</p></li><li><p><strong>Defending Against Deportation Orders:</strong> If you are facing a deportation order, we will vigorously defend your case in immigration court, exploring all options to avoid deportation and keep you in the country.</p></li><li><p><strong>Bond Hearings:</strong> If you are detained by Immigration and Customs Enforcement (ICE), we can help you request a bond hearing to secure your release while your removal case is pending.</p></li><li><p><strong>Appeals of Deportation Orders:</strong> If you have been ordered removed from the U.S., we can help you file an appeal and seek to overturn the decision, presenting new evidence or legal arguments to support your case.</p></li></ul><p><br></p><p><strong>Protecting Your Rights and Your Future</strong><br>Being in removal proceedings is a serious matter, but with the right legal defense, there may be options to remain in the U.S. Marinoff &amp; Associates is dedicated to fighting for your rights and working to achieve the best possible outcome for your case. Whether you are seeking cancellation of removal, asylum, or another form of relief, we will provide you with aggressive representation and compassionate support throughout the process.</p><p>If you are facing removal or deportation, contact Marinoff &amp; Associates today to schedule a consultation. Our experienced removal defense attorneys are here to evaluate your case, discuss your options, and help you fight to remain in the United States.<br></p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"d0f95fac-2697-43a3-9669-c27acfbe41ef","name":"","text":"","type":"image","column":"right","settings":{"alt":"Removal & Deportation Defense Attorney","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/Stock_Photos/1781989840772_Positive_Testimonial.png","size":"75","effect":"none","newTab":"false","linkUrl":"","variant":"image","alignment":"center","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opa