ng","size":"75","effect":"none","newTab":"false","linkUrl":"","variant":"logo","alignment":"left","borderColor":"#c5a059","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"2","horizontalOffset":"0"}}],"alignment":"left","canonical":true,"isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"center","center":"left"},"cellShadow":{"left":"none","right":"none","center":"none"},"cellVAlign":{"left":"top","right":"top","center":"center"},"cellOpacity":{"left":"1","right":"1","center":"1"},"cellPadding":{"left":"0","right":"0","center":"0"},"marginBottom":"20","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false","center":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","savedSectionId":"saved_section_1781826409772_rcsh6r","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"center":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#d9e4ef","right":"#999999","center":"#ffffff"},"cellBorderStyle":{"left":"solid","right":"solid","center":"solid"},"cellBorderWidth":{"left":"0","right":"0","center":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"0","right":"14","center":"20"},"cellMobileHidden":{"left":"false","right":"false","center":"false"},"cellDesktopHidden":{"left":"false","right":"false","center":"false"},"cellVerticalMargin":{"left":"0","right":"0","center":"0"}},{"id":"348037cd-5139-48ea-86f2-3a03d32d4242","title":"Content Block 1","layout":"two-column","locked":false,"modules":[{"id":"module-ae640e95-5fca-45de-aaea-7ba97866a0d2","name":"","text":"<h1>Asylum</h1><h2>Protection. Safety. A Chance to Build a New Future.</h2><p>Seeking asylum is about far more than immigration status—it is about safety, dignity, and the fundamental human right to live free from persecution. Many individuals and families come to the United States fleeing violence, political oppression, religious persecution, or threats that place their lives and well-being at risk. The decision to leave your home country is never easy, and the uncertainty of the immigration process can be overwhelming.</p><p>At <strong>Marinoff &amp; Associates, P.C.,</strong> we understand that behind every asylum case is a deeply personal story of hardship, courage, and hope. We are committed to helping individuals and families pursue protection in the United States through compassionate guidance, knowledgeable representation, and personalized legal strategies. Our team is here to listen to your story, explain your options, and advocate for your rights every step of the way.</p><h2>What Is Asylum?</h2><p>Asylum is a form of legal protection available to individuals who are unable or unwilling to return to their home country because they have suffered persecution or have a well-founded fear of future persecution. Persecution may be based on race, religion, nationality, political opinion, or membership in a particular social group.</p><p>Asylum can provide protection from deportation and may allow eligible individuals to remain legally in the United States, obtain work authorization, petition for certain family members, and eventually pursue lawful permanent residency and citizenship.</p><p>Because asylum cases involve complex legal requirements and strict filing deadlines, obtaining experienced legal guidance as early as possible is extremely important.</p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"86aa7632-5560-46ab-b6f7-d401d6ff04a3","name":"Asylum","text":"","type":"image","column":"right","settings":{"alt":"Asylum attorney","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/Stock_Photos/1781877027784_Immigration_-_Personal_Touch.png","size":"90","altText":"Image","linkUrl":"","imageUrl":"","maxWidth":"100","alignment":"center","maxWidthPx":"0","aspectRatio":"auto","borderRadius":"20","imageAssetId":"289","overlayOpacity":"0","verticalOffset":"0","borderThickness":"1","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#999999","right":"#999999"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"14","right":"14"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"section-1f91ac86-7404-42e9-a918-2e3386311456","title":"Content Block 2","layout":"two-column","locked":false,"modules":[{"id":"module-aeeafe39-cf70-4bfb-a824-7a8e28eb9f48","name":"","text":"<h2><strong>Why Choose Marinoff &amp; Associates?</strong></h2><ol><li><p><strong>Experienced Asylum Attorneys: </strong>Our team specializes in asylum law and has a proven track record of helping individuals successfully obtain asylum in the U.S. We understand the intricacies of the asylum process and are committed to achieving the best possible outcome for you.</p></li><li><p><strong>Personalized Legal Support: </strong>We know that each asylum case is unique. Our attorneys will work closely with you to understand your personal circumstances and develop a tailored legal strategy that maximizes your chances of success.</p></li><li><p><strong>Compassionate Guidance: </strong>We understand that applying for asylum is often a deeply emotional and challenging experience. Our team is dedicated to providing the support and understanding you need to navigate this difficult process, ensuring you feel heard and empowered throughout.</p></li><li><p><strong>Aggressive Representation: </strong>If your asylum claim is contested or if you are facing a denial, we will vigorously defend your case, advocating for your right to remain in the U.S. and presenting a strong case for asylum.</p></li></ol><p></p>","type":"text","column":"right","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"module-665ef090-ec37-4f92-b4b4-307af246259f","name":"","text":"","type":"image","column":"left","settings":{"alt":"Humanitarian immigration lawyer","url":"https://irp.cdn-website.com/03f0d32c/dms3rep/multi/pexels-photo-19263993.jpeg","size":"90","effect":"none","newTab":"false","linkUrl":"","variant":"image","alignment":"center","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"transparent","right":"transparent"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"24","right":"24"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"4266a753-2f01-487a-834e-02f427377465","title":"Content Block 2","layout":"two-column","locked":false,"modules":[{"id":"a39ed720-30eb-490e-a1af-bd3d629b2dc2","name":"","text":"<h2><strong>How We Can Help:</strong></h2><ul><li><p><strong>Filing Your Asylum Application: </strong>We assist with the preparation and submission of your asylum application (Form I-589) to ensure that all the necessary documentation is included and the application is complete.</p></li><li><p><strong>Asylum Interview Preparation: </strong>If you are applying for asylum through the affirmative process, we will help you prepare for your asylum interview with U.S. Citizenship and Immigration Services (USCIS), ensuring that you present your case clearly and effectively.</p></li><li><p><strong>Defensive Asylum Applications: </strong>If you are in removal proceedings and seeking asylum as a defense against deportation, we can help you navigate the defensive asylum process in immigration court, presenting your case before an immigration judge.</p></li><li><p><strong>Gathering Evidence: </strong>We will help you collect the evidence necessary to support your asylum claim, including affidavits, country condition reports, witness testimony, and other documentation that demonstrates the persecution you have faced or fear facing.</p></li><li><p><strong>Appeals and Denials: </strong>If your asylum claim is denied or if you face an adverse decision, we can assist with filing an appeal to the Board of Immigration Appeals (BIA) or pursuing other legal remedies to challenge the decision.</p></li><li><p><strong>Work Authorization: </strong>If you have filed for asylum and are waiting for your application to be processed, we can help you apply for work authorization, allowing you to support yourself and your family while your asylum claim is pending.</p></li><li><p><strong>Asylum for Family Members: </strong>We can also assist you in including your family members in your asylum claim, helping them to receive protection and legal status as part of your case.</p></li></ul><h2><strong>Protecting Your Right to Safety and Freedom</strong></h2><p>Asylum is a crucial form of protection for individuals fleeing violence, persecution, or other life-threatening situations. At Marinoff &amp; Associates, we are committed to helping you navigate the complex asylum process and secure the protection you need to rebuild your life in the U.S.</p><p>If you are seeking asylum or need assistance with any aspect of the asylum process, contact Marinoff &amp; Associates today. Our experienced immigration attorneys are here to evaluate your case, provide you with the legal expertise you need, and help you fight for the safety and freedom you deserve.</p><p><strong>Protecting Families. Creating Opportunities. Building Futures.</strong></p><p><strong>Contact Marinoff &amp; Associates, P.C. today to schedule a consultation and learn how we can help you achieve your immigration goals.</strong></p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"2dd69dbb-097d-4960-89fc-e8a622998eae","name":"","text":"","type":"image","column":"right","settings":{"alt":"Asylum immigration lawyer Colorado","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/Stock_Photos/1781989840772_Positive_Testimonial.png","size":"75","effect":"none","newTab":"false","linkUrl":"","variant":"image","alignment":"center","borderColor":"#0f4f8f","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cel