ng","size":"75","effect":"none","newTab":"false","linkUrl":"","variant":"logo","alignment":"left","borderColor":"#c5a059","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"2","horizontalOffset":"0"}}],"alignment":"left","canonical":true,"isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"center","center":"left"},"cellShadow":{"left":"none","right":"none","center":"none"},"cellVAlign":{"left":"top","right":"top","center":"center"},"cellOpacity":{"left":"1","right":"1","center":"1"},"cellPadding":{"left":"0","right":"0","center":"0"},"marginBottom":"20","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false","center":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","savedSectionId":"saved_section_1781826409772_rcsh6r","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"center":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#d9e4ef","right":"#999999","center":"#ffffff"},"cellBorderStyle":{"left":"solid","right":"solid","center":"solid"},"cellBorderWidth":{"left":"0","right":"0","center":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"0","right":"14","center":"20"},"cellMobileHidden":{"left":"false","right":"false","center":"false"},"cellDesktopHidden":{"left":"false","right":"false","center":"false"},"cellVerticalMargin":{"left":"0","right":"0","center":"0"}},{"id":"348037cd-5139-48ea-86f2-3a03d32d4242","title":"About Marinoff & Associates, P.C.","layout":"two-column","locked":false,"modules":[{"id":"module-ae640e95-5fca-45de-aaea-7ba97866a0d2","name":"","text":"<h1>About Us</h1><h2>Protecting Rights. Guiding Families. Building Futures.</h2><p>At <strong>Marinoff &amp; Associates, P.C.</strong>, we believe that legal representation is about far more than statutes, courtrooms, and paperwork. It is about people. Behind every legal matter is an individual, a family, and a future that deserves protection, respect, and thoughtful guidance.</p><p>For years, our firm has built a reputation throughout Colorado for providing knowledgeable, compassionate, and results-driven legal representation. We understand that legal challenges often arise during some of life''s most stressful and uncertain moments.</p><p>Whether you are facing criminal charges, navigating a family transition, or pursuing an immigration matter, the decisions you make today can have lasting consequences. That is why we approach every case with careful preparation, honest communication, and a genuine commitment to helping our clients move forward with confidence.</p><p><strong>With offices in Westminster, Brighton, and Greeley, we proudly represent individuals and families throughout Colorado in the areas of Criminal Law and Immigration Law</strong>.</p><p>Our attorneys understand that no two cases are alike. Every client''s circumstance, concerns, and goals are unique, and we believe your legal strategy should reflect that reality. We take the time to listen, answer your questions, and develop practical solutions tailored to your specific situation.</p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"86aa7632-5560-46ab-b6f7-d401d6ff04a3","name":"Justice","text":"","type":"image","column":"right","settings":{"alt":"","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1782965758172_Brandon_Marinoff_Team_1402x1122_960x768.jpg","size":"90","altText":"Image","linkUrl":"","imageUrl":"","maxWidth":"100","alignment":"right","maxWidthPx":"0","aspectRatio":"auto","borderColor":"#0f4f8f","borderRadius":"20","imageAssetId":"289","overlayOpacity":"0","verticalMargin":"50","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#999999","right":"#999999"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"14","right":"14"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"75"}},{"id":"section-225b4037-190e-4963-91fb-690e51cc83ca","title":"Learn More About Brandon Marinoff","layout":"single","locked":false,"modules":[{"id":"module-d06c9358-9ff5-4376-85ed-34f3c8b441bf","name":"","text":"","type":"image","column":"main","settings":{"alt":"","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1783011348727_About_Brandon_Marinoff_1896x829_960x420.jpg","size":"66","effect":"none","newTab":"false","linkUrl":"/brandon-marinoff-bio","variant":"image","alignment":"center","borderColor":"#fff5db","borderRadius":"20","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"main":"left"},"cellShadow":{"main":"none"},"cellVAlign":{"main":"top"},"cellOpacity":{"main":"1"},"cellPadding":{"main":"40"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"main":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#000000","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"main":{"mode":"gradient","color":"#ffffff","color2":"#d6c199","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"main":"transparent"},"cellBorderStyle":{"main":"solid"},"cellBorderWidth":{"main":"0"},"rowBorderRadius":"0","cellBorderRadius":{"main":"24"},"cellMobileHidden":{"main":"false"},"cellDesktopHidden":{"main":"false"},"cellVerticalMargin":{"main":"0"}},{"id":"section-1f91ac86-7404-42e9-a918-2e3386311456","title":"A Client-First Approach","layout":"two-column","locked":false,"modules":[{"id":"module-665ef090-ec37-4f92-b4b4-307af246259f","name":"","text":"","type":"image","column":"left","settings":{"alt":"","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/Stock_Photos/1781989833371_Every_Case_is_Personal.png","size":"90","effect":"none","newTab":"false","linkUrl":"","variant":"image","borderColor":"#0f4f8f","borderRadius":"20","mobileHidden":"false","desktopHidden":"false","verticalMargin":"40","verticalOffset":"0","borderThickness":"0","horizontalOffset":"0"}},{"id":"module-aeeafe39-cf70-4bfb-a824-7a8e28eb9f48","name":"A Client-First Approach","text":"<h2>A Client-First Approach</h2><p>At Marinoff &amp; Associates, our clients are never treated like case numbers. We take the time to listen, understand your circumstances, answer your questions, and explain your legal options in clear and practical terms.</p><p>We understand that legal challenges can be stressful, emotional, and overwhelming. Our goal is to provide not only experienced legal representation but also peace of mind. We strive to create an environment where our clients feel informed, supported, and confident throughout every stage of the legal process.</p><h2>Practice Areas</h2><h3><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://brandonmarinoff.com/criminal-law/\">Criminal Defense</a></h3><p>When your freedom and reputation are on the line, you need an experienced advocate in your corner. We aggressively protect our clients'' rights and work tirelessly to pursue the best possible outcome in every criminal matter. <a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://brandonmarinoff.com/criminal-law/\">Learn More.</a></p><h3><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://brandonmarinoff.com/immigration-law/\">Immigration Law</a></h3><p>The immigration process can be complex and intimidating. We help individuals and families pursue opportunities in the United States through family petitions, citizenship and naturalization, student visas, adjustment of status, VAWA petitions, and other immigration matters.<a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://brandonmarinoff.com/immigration-law/\"> Learn More.</a></p><p></p>","type":"text","column":"right","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"left"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"18"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"transparent","right":"transparent"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"24","right":"24"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"b56a84d6-780b-4e49-9afb-c632dfbf0c53","title":"Serving Communities Across Colorado","layout":"two-column","locked":false,"modules":[{"id":"ed8cac42-c4a9-45a1-9113-d7f3d42b3d40","name":"Serving Communities Across Colorado","text":"<h2>Serving Communities Across Colorado</h2><p>With offices conveniently located in Westminster, Brighton, and Greeley, Marinoff &amp; Associates proudly serves clients throughout Colorado. We are honored to represent individuals and families from diverse backgrounds and are committed to providing accessible, high-quality legal services to the communities we serve.</p>","type":"text","column":"left","settings":{"variant":"intro","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0"}},{"id":"button-1782943107645-0","name":"Request a Consultation","text":"Request a Consultation","type":"button","column":"right","settings":{"href":"/contact","variant":"primary","fontSize":"24","paddingX":"50","paddingY":"20","alignment":"center","marginTop":"80","textColor":"#0f4f8f","buttonSize":"large","marginLeft":"0","borderColor":"#0f4f8f","borderStyle":"solid","buttonColor":"#58d9f9","marginRight":"0","borderRadius":"20","marginBottom":"40","mobileHidden":"false","desktopHidden":"false","textHoverColor":"#ffffff","verticalMargin":"40","buttonHoverColor":"#0f4f8f","buttonBackgroundMode":"color","buttonBackgroundColor":"#58d9f9","buttonBackgroundColor2":"#eaf4ff","buttonBackgroundImageUrl":"","buttonBackgroundStyleKey":""}}],"alignment":"left","isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"center"},"cellShadow":{"left":"none","right":"none"},"cellVAlign":{"left":"top","right":"top"},"cellOpacity":{"left":"1","right":"1"},"cellPadding":{"left":"18","right":"20"},"marginBottom":"0","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"transparent","right":"transparent"},"cellBorderStyle":{"left":"solid","right":"solid"},"cellBorderWidth":{"left":"0","right":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"24","right":"24"},"cellMobileHidden":{"left":"false","right":"false"},"cellDesktopHidden":{"left":"false","right":"false"},"cellVerticalMargin":{"left":"0","right":"0"}},{"id":"5f5814fc-d69a-4845-a9cc-4aa26d69a774","title":"Our Commitment","layout":"two-column","locked":false,"modules":[{"id":"25567e08-b7e0-4472-82ad-d31fdc2e37b8","name":"Serving Communities Across Colorado","text":"<h2>Our Commitment</h2><p>At Marinoff &amp; Associates, our mission is simple:</p><p><strong>Protecting Rights. Defending Futures. Helping Good People Through Difficult Times.</strong></p><p>Every case is personal. Every client matters. When you need trusted legal guidance and an attorney who genuinely cares about your future, Marinoff &amp; Associates is here to stand beside you every step of the way.</p><p><strong>Marinoff &amp; Associates, P.C.</strong><br><strong>Attorneys at Law</strong><br>Westminster • Brighton • Greeley<br><strong>Experienced. Dedicated. Here for You.</strong></p><p></p><p><strong>Schedule a confidential consultation today and discover how Marinoff &amp; Associates can help protect your rights, your family, and your future.</strong></p><p style=\"font-size: 1.1rem; line-height: 1.6; color: rgb(71, 85, 105);\">📞 <strong>Call:</strong> 720-373-3508 <em>(Se Habla Español)</em> or 720-216-4766<br>📍 <strong>Offices:</strong> Westminster • Brighton • Greeley<br>🌐 <strong>Website:</strong> <a target=\"_blank\" rel=\"noopener noreferrer\" href=\"http://www.brandonmarinoff.com\">www.brandonmarinoff.com</a></p><p style=\"font-size: 1.1rem; line-height: 1.6; color: rgb(71, 85, 105);\"><strong>Marinoff &amp; Associates, P.C.</strong><br><em>Dedicated Advocates. Trusted Counsel. Results That Matter.</em><br><strong>Your Rights. Your Family. Your Future.