lumn":"left","settings":{"alt":"","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/Logo/1782843726319_Marinoff_and_Associates_-_Criminal_Defense_and_Immigration_Law_Firm.png","size":"75","effect":"none","newTab":"false","linkUrl":"","variant":"logo","alignment":"left","borderColor":"#c5a059","borderRadius":"18","mobileHidden":"false","desktopHidden":"false","verticalMargin":"0","verticalOffset":"0","borderThickness":"2","horizontalOffset":"0"}}],"alignment":"left","canonical":true,"isPrivate":false,"marginTop":"0","background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"cellHAlign":{"left":"left","right":"center","center":"left"},"cellShadow":{"left":"none","right":"none","center":"none"},"cellVAlign":{"left":"top","right":"top","center":"center"},"cellOpacity":{"left":"1","right":"1","center":"1"},"cellPadding":{"left":"0","right":"0","center":"0"},"marginBottom":"20","mobileHidden":"false","mobileLayout":"stack","cellIsPrivate":{"left":"false","right":"false","center":"false"},"desktopHidden":"false","overlayScreen":{"opacity":100,"background":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"rowBorderColor":"#ffffff","rowBorderStyle":"solid","rowBorderWidth":"0","savedSectionId":"saved_section_1781826409772_rcsh6r","cellBackgrounds":{"left":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"right":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""},"center":{"mode":"none","color":"#ffffff","color2":"#eaf4ff","opacity":100,"imageUrl":"","styleKey":"","imageAssetId":""}},"cellBorderColor":{"left":"#d9e4ef","right":"#999999","center":"#ffffff"},"cellBorderStyle":{"left":"solid","right":"solid","center":"solid"},"cellBorderWidth":{"left":"0","right":"0","center":"0"},"rowBorderRadius":"0","cellBorderRadius":{"left":"0","right":"14","center":"20"},"cellMobileHidden":{"left":"false","right":"false","center":"false"},"cellDesktopHidden":{"left":"false","right":"false","center":"false"},"cellVerticalMargin":{"left":"0","right":"0","center":"0"}},{"id":"section-theft-fraud-body-20260717","layout":"single","locked":false,"modules":[{"id":"module-theft-fraud-body-20260717","name":"","type":"text","column":"","text":"<h1>Theft/Fraud</h1><h2>How Marinoff &amp; Associates Can Help</h2><p>At Marinoff &amp; Associates, we understand that being accused of theft, fraud, or embezzlement can be a life-altering experience. These charges can affect your reputation, your employment, your professional licenses, and your immigration status, and even a first-time offense deserves a serious, careful defense.</p><p>Theft and fraud cases often involve financial records, transactions, workplace relationships, and questions of intent or ownership. Our experienced legal team reviews every detail to identify weaknesses in the prosecution’s case and build the strongest available defense.</p><h2>What Are Theft &amp; Fraud Charges?</h2><p>Theft and fraud charges can take many forms, including shoplifting, larceny, auto theft, identity theft, embezzlement, wire fraud, insurance fraud, credit card fraud, and theft or financial misconduct in the workplace, and more. These are only examples. We can help with these and any other related charge.</p><h2>How We Can Help:</h2><ul><li><p><strong>Comprehensive Case Review:</strong> We can examine every detail of your case, including financial records, digital evidence, witness statements, contracts, and police reports, to identify defenses such as lack of intent, mistaken identity, authorization, or insufficient evidence.</p></li><li><p><strong>Court Representation:</strong> We can represent you at all stages of the legal process, from investigation and pre-trial hearings through trial, working to protect your rights at every step.</p></li><li><p><strong>Negotiations &amp; Settlements:</strong> In some cases, we may work to negotiate reduced charges or a resolution that minimizes penalties and protects your record.</p></li><li><p><strong>Mitigating Consequences:</strong> If a conviction cannot be avoided, we explore every opportunity to reduce penalties, including alternatives to incarceration where available.</p></li></ul><p>If you or a loved one is facing a theft, fraud, or embezzlement charge, contact Marinoff &amp; Associates today for a consultation.</p>","settings":{}}]},{"id":"b22a4855-b26c-43e3-9a2c-06dcfd7af403","title":"Footer","layout":"three-column","locked":false,"modules":[{"id":"module_1781127640512_v48dw","name":"Contact Us","text":"<h3><span style=\"font-size: 20px; color: rgb(0, 0, 0);\"><strong>Contact Us</strong></span></h3><p><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">303.619.1978‬</span></p><p><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">720.621.7635 - Se Habla Español</span></p><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"mailto:bmarinoff@brandonmarinoff.com\"><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">bmarinoff@brandonmarinoff.com</span></a></p><p></p><h3><span style=\"font-size: 20px; color: rgb(0, 0, 0);\"><strong>Address</strong></span></h3><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://www.brandonmarinoff.com/\"><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">12207 Pecos St. Suite 700</span></a></p><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://www.brandonmarinoff.com/\"><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">Westminster, CO. 80234</span></a></p>","type":"text","column":"right","settings":{"text":"Contact Us","align":"left","textColor":"#173c61","headlineId":"","headingLevel":"H3"}},{"id":"module_1781293635840_3p0km","name":"Logo","text":"","type":"image","column":"left","settings":{"alt":"Brandon Marinoff & Associates","url":"https://astujhe2hvjqd0kf.public.blob.v