rowBorderRadius":"0","cellBorderRadius":{"left":"0","right":"14","center":"20"},"cellMobileHidden":{"left":"false","right":"false","center":"false"},"cellDesktopHidden":{"left":"false","right":"false","center":"false"},"cellVerticalMargin":{"left":"0","right":"0","center":"0"}},{"id":"section-restraining-orders-body-20260717","layout":"single","locked":false,"modules":[{"id":"module-restraining-orders-body-20260717","name":"","type":"text","column":"","text":"<h1>Restraining Orders</h1><h2>How Marinoff &amp; Associates Can Help</h2><p>At Marinoff &amp; Associates, we understand that protection order proceedings move fast and the stakes are high on both sides. An order can affect your home, your children, your firearms rights, and your record, often before you have had a chance to tell your side.</p><p>Whether you are responding to a protection order that has been filed against you or seeking protection for yourself or your family, our experienced legal team can guide you through the process.</p><h2>What Are Restraining Order Matters?</h2><p>Restraining order matters include temporary and permanent civil protection orders, mandatory criminal protection orders, alleged violations of existing orders, and requests to modify or lift orders, and more. These are only examples. We can help with these and any other related charge.</p><h2>How We Can Help:</h2><ul><li><p><strong>Hearing Representation:</strong> We can represent you at protection order hearings, presenting evidence and cross-examining witnesses so the court hears the full story.</p></li><li><p><strong>Responding to an Order:</strong> If an order has been entered against you, we can help you respond, seek modifications, and work to avoid a permanent order where the facts do not support one.</p></li><li><p><strong>Seeking Protection:</strong> If you need protection, we can help you prepare and present a clear, well-documented request to the court.</p></li><li><p><strong>Violation Defense:</strong> If you are accused of violating an order, we can defend the criminal charge and work to minimize its consequences.</p></li></ul><p>If you are involved in a protection order matter, contact Marinoff &amp; Associates today for a consultation.</p>","settings":{}}]},{"id":"b22a4855-b26c-43e3-9a2c-06dcfd7af403","title":"Footer","layout":"three-column","locked":false,"modules":[{"id":"module_1781127640512_v48dw","name":"Contact Us","text":"<h3><span style=\"font-size: 20px; color: rgb(0, 0, 0);\"><strong>Contact Us</strong></span></h3><p><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">303.619.1978‬</span></p><p><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">720.621.7635 - Se Habla Español</span></p><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"mailto:bmarinoff@brandonmarinoff.com\"><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">bmarinoff@brandonmarinoff.com</span></a></p><p></p><h3><span style=\"font-size: 20px; color: rgb(0, 0, 0);\"><strong>Address</strong></span></h3><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://www.brandonmarinoff.com/\"><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">12207 Pecos St. Suite 700</span></a></p><p><a target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://www.brandonmarinoff.com/\"><span style=\"font-size: 20px; color: rgb(0, 0, 0);\">Westminster, CO. 80234</span></a></p>","type":"text","column":"right","settings":{"text":"Contact Us","align":"left","textColor":"#173c61","headlineId":"","headingLevel":"H3"}},{"id":"module_1781293635840_3p0km","name":"Logo","text":"","type":"image","column":"left","settings":{"alt":"Brandon Marinoff & Associates","url":"https://astujhe2hvjqd0kf.public.blob.vercel-storage.com/APP_Assets/Image/1781469490414_Marinoff_and_Associates_Logo-1920.webp","size":"75","altText":"Image","linkUrl":"","imageUrl":"","maxWidth":"40","alignment":"center","maxWidthPx":"0","aspectRatio":"auto","borderRadius":"0","imageAssetId":"412","overlayOpacity":"0","verticalMargin":"50","